app.use(abuseTrackerMiddleware({
  limitPaths: ["/market/search", "/api/vision/analyze", "/upload/presign", "/vision/enrich"],
}));
// Honeytoken bot detection — absent/invalid X-Ev-Client-Token → shadow-ban
