// -------------------- Request logger + request id --------------------
app.use((req, res, next) => {
  const inboundRid = safeStr(req.headers["x-request-id"], 120) || null;
  const rid = inboundRid || crypto.randomBytes(8).toString("hex");
  const traceId =
    safeStr(req.headers["x-trace-id"], 160) ||
    safeStr(req.inboundTrace, 200) ||
    rid;

  req.rid = rid;
  req.traceId = traceId;

  res.setHeader("x-request-id", rid);
  res.setHeader("x-trace-id", traceId);

  const actor = getRequestActor(req);
  const routeKey = normalizeRouteForMetrics(req.path);
  const startNs = process.hrtime.bigint();

  res.on("finish", () => {
    const durationMs =
      Number(process.hrtime.bigint() - startNs) / 1_000_000;

    incrementMetric("http_requests_total", {
      route: routeKey,
      method: req.method,
      status: String(res.statusCode),
    });

    observeLatencyMetric("http_request_duration_ms", durationMs, {
      route: routeKey,
      method: req.method,
    });

    if (res.statusCode >= 500) {
      incrementMetric("http_5xx_total", {
        route: routeKey,
        method: req.method,
      });
    }

    logStructured(
      res.statusCode >= 500
        ? "error"
        : durationMs > 4000
        ? "warn"
        : "info",
      "http_request_complete",
      {
        rid,
        traceId,
        method: req.method,
        route: routeKey,
        originalUrl: req.originalUrl,
        statusCode: res.statusCode,
        durationMs: Math.round(durationMs * 100) / 100,
        ip: actor.ip,
        userId: actor.userId,
        deviceId: actor.deviceId,
        edgeRegion: req.edgeRegion,
      }
    );

    if (durationMs > 4000) {
      Promise.resolve()
        .then(() =>
          emitOpsAlert(
            "slow_request",
            {
              rid,
              route: req.originalUrl,
              method: req.method,
              statusCode: res.statusCode,
              durationMs: Math.round(durationMs * 100) / 100,
            },
            { severity: "warn", cooldownMs: 60_000 }
          )
        )
        .catch(() => {});
    }

    recordRouteObservation({
      route: req.originalUrl,
      method: req.method,
      statusCode: res.statusCode,
      durationMs: Math.round(durationMs * 100) / 100,
      ip: actor.ip,
      userId: actor.userId,
      rid,
    });

    recordGlobalRequestObservation({
      route: req.originalUrl,
      method: req.method,
      statusCode: res.statusCode,
      durationMs: Math.round(durationMs * 100) / 100,
    });
  });

  next();
});

const MAX_UPLOAD_BYTES = Number(
  process.env.MAX_UPLOAD_BYTES || 10 * 1024 * 1024
);

const STORAGE_ROOT = path.resolve(process.env.STORAGE_ROOT || "./storage");
const SCAN_STORAGE_ROOT = path.join(STORAGE_ROOT, "scan");
const SCAN_ORIGINAL_ROOT = path.join(SCAN_STORAGE_ROOT, "original");
const SCAN_PROCESSED_ROOT = path.join(SCAN_STORAGE_ROOT, "processed");
const SCAN_THUMB_ROOT = path.join(SCAN_STORAGE_ROOT, "thumb");
const SCAN_EMBEDDING_ROOT = path.join(SCAN_STORAGE_ROOT, "embeddings");
const SCAN_MANIFEST_ROOT = path.join(SCAN_STORAGE_ROOT, "manifest");

// S3 client is created on first use (AWS SDK lazy-loaded above).
let _s3Client = null;
async function getS3Client() {
  if (_s3Client) return _s3Client;
  if (
    OBJECT_STORE_PROVIDER !== "s3" ||
    !OBJECT_STORE_BUCKET ||
    !OBJECT_STORE_ACCESS_KEY_ID ||
    !OBJECT_STORE_SECRET_ACCESS_KEY
  ) return null;
  const { S3Client } = await getS3SDK();
  _s3Client = new S3Client({
    region: OBJECT_STORE_REGION || "auto",
    endpoint: OBJECT_STORE_ENDPOINT || undefined,
    forcePathStyle: OBJECT_STORE_FORCE_PATH_STYLE,
    credentials: {
      accessKeyId: OBJECT_STORE_ACCESS_KEY_ID,
      secretAccessKey: OBJECT_STORE_SECRET_ACCESS_KEY,
    },
  });
  return _s3Client;
}
// Legacy sync reference kept for canUseS3ObjectStore() truthiness checks — always null at boot.
// Actual send() calls below use getS3Client() + getS3SDK() instead.
const s3Client = null;

const PREPROCESS_MAX_EDGE = Number(process.env.PREPROCESS_MAX_EDGE || 768);
const PREPROCESS_JPEG_QUALITY = Number(
  process.env.PREPROCESS_JPEG_QUALITY || 82
);

const BG_JOB_CONCURRENCY = Math.max(
  1,
  Number(process.env.BG_JOB_CONCURRENCY || 2)
);

const BG_JOB_MAX_AGE_MS = Number(
  process.env.BG_JOB_MAX_AGE_MS || 6 * 60 * 60 * 1000
);

// -------------------- Multer (images) --------------------
const upload = multer({
  storage: multer.memoryStorage(),
limits: {
  fileSize: MAX_UPLOAD_BYTES,
  files: 1
},
  fileFilter: (_req, file, cb) => {
    const ok = /^image\/(jpeg|jpg|png|webp|heic|heif)$/i.test(file.mimetype);
    cb(ok ? null : new Error("invalid_file_type"), ok);
  },
});

function extensionFromMime(mimetype = "") {
  const m = String(mimetype || "").toLowerCase();

  if (m.includes("jpeg") || m.includes("jpg")) return "jpg";
  if (m.includes("png")) return "png";
  if (m.includes("webp")) return "webp";
  if (m.includes("heic")) return "heic";
  if (m.includes("heif")) return "heif";

  return "bin";
}

function scanOriginalKey(imageHash, ext = "bin") {
  return `scan/original/${imageHash}.${ext}`;
}

function scanProcessedKey(imageHash) {
  return `scan/processed/${imageHash}.jpg`;
}

function scanThumbKey(imageHash) {
  return `scan/thumb/${imageHash}.jpg`;
}

function scanEmbeddingKey(imageHash) {
  return `scan/embeddings/${imageHash}.json`;
}

function scanManifestKey(imageHash) {
  return `scan/manifest/${imageHash}.json`;
}

function storagePathFromKey(key = "") {
  return path.join(STORAGE_ROOT, ...String(key).split("/"));
}

async function ensureDir(dir) {
  await fs.mkdir(dir, { recursive: true });
}

async function fileExists(absPath) {
  try {
    await fs.access(absPath);
    return true;
  } catch {
    return false;
  }
}

async function ensureScanStorage() {
  await Promise.all([
    ensureDir(SCAN_STORAGE_ROOT),
    ensureDir(SCAN_ORIGINAL_ROOT),
    ensureDir(SCAN_PROCESSED_ROOT),
    ensureDir(SCAN_THUMB_ROOT),
    ensureDir(SCAN_EMBEDDING_ROOT),
    ensureDir(SCAN_MANIFEST_ROOT),
  ]);
}

const scanStorageReady = ensureScanStorage();

function canUseS3ObjectStore() {
  return (
    OBJECT_STORE_PROVIDER === "s3" &&
    !!OBJECT_STORE_BUCKET &&
    !!OBJECT_STORE_ACCESS_KEY_ID &&
    !!OBJECT_STORE_SECRET_ACCESS_KEY
  );
}

function guessMimeFromKey(key = "") {
  const lower = String(key || "").toLowerCase();
  if (lower.endsWith(".jpg") || lower.endsWith(".jpeg")) return "image/jpeg";
  if (lower.endsWith(".png")) return "image/png";
  if (lower.endsWith(".webp")) return "image/webp";
  if (lower.endsWith(".heic")) return "image/heic";
  if (lower.endsWith(".heif")) return "image/heif";
  if (lower.endsWith(".json")) return "application/json";
  return "application/octet-stream";
}

function objectStorePublicUrl(key = "") {
  if (!key) return null;
  if (OBJECT_STORE_PUBLIC_BASE_URL) {
    return `${OBJECT_STORE_PUBLIC_BASE_URL}/${String(key).replace(/^\/+/, "")}`;
  }
  return null;
}

function normalizeObjectMetadata(metadata = {}) {
  const out = {};
  for (const [k, v] of Object.entries(metadata || {})) {
    if (v == null) continue;
    out[String(k).slice(0, 64)] = String(v).slice(0, 256);
  }
  return out;
}

async function streamToBuffer(stream) {
  const chunks = [];
  for await (const chunk of stream) {
    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
  }
  return Buffer.concat(chunks);
}

async function objectStorePutBuffer(
  key,
  buffer,
  contentType = "application/octet-stream",
  metadata = {}
) {
  if (canUseS3ObjectStore()) {
    try {
      const [client, { PutObjectCommand }] = await Promise.all([getS3Client(), getS3SDK()]);
      await client.send(
        new PutObjectCommand({
          Bucket: OBJECT_STORE_BUCKET,
          Key: key,
          Body: buffer,
          ContentType: contentType,
          Metadata: normalizeObjectMetadata(metadata),
        })
      );
      return {
        key,
        url: objectStorePublicUrl(key),
        provider: "s3",
      };
    } catch (s3Err) {
      console.warn("⚠️ S3 put failed, falling back to local:", s3Err?.message || s3Err);
    }
  }

  await writeBufferIfMissing(key, buffer);
  return {
    key,
    url: objectStorePublicUrl(key),
    provider: "local",
  };
}

async function objectStoreReadBuffer(key) {
  if (!key) return null;

  try {
    if (canUseS3ObjectStore()) {
      const [client, { GetObjectCommand }] = await Promise.all([getS3Client(), getS3SDK()]);
      const out = await client.send(
        new GetObjectCommand({
          Bucket: OBJECT_STORE_BUCKET,
          Key: key,
        })
      );

      return await streamToBuffer(out.Body);
    }

    const absPath = storagePathFromKey(key);
    return await fs.readFile(absPath);
  } catch {
    return null;
  }
}

// Downscale a scan image to a max edge of VISION_MAX_EDGE_PX (default 800) and
// re-encode as JPEG quality 85 before sending to the vision model. Saves ~2-3s
// per scan from reduced upload + decode time. Returns the original buffer
// untouched when the image is already small, when the env is disabled, or when
// sharp throws (so we never block a scan on a re-encode error).
const VISION_MAX_EDGE_PX = Number(process.env.VISION_MAX_EDGE_PX || 800);
// Mode-specific max-edge overrides. item/prop modes use a smaller edge —
// 640px is enough for object identification and reduces OpenAI token count,
// which cuts response time on warm cache. label/barcode/mark modes keep a
// larger edge so fine text stays readable.
const VISION_ITEM_MAX_EDGE     = Number(process.env.VISION_ITEM_MAX_EDGE || 640);
const VISION_TEXT_MAX_EDGE     = Number(process.env.VISION_TEXT_MAX_EDGE || 800);
const VISION_DOWNSCALE_ENABLED = String(process.env.VISION_DOWNSCALE_ENABLED || "true").toLowerCase() !== "false";
async function prepareVisionBuffer(buffer, rid = "", maxEdgePx = VISION_MAX_EDGE_PX) {
  if (!VISION_DOWNSCALE_ENABLED) return buffer;
  if (!Buffer.isBuffer(buffer) || buffer.length < 4000) return buffer;
  try {
    const sharp = await getSharp();
    const base = sharp(buffer, { failOn: "none" }).rotate();
    const meta = await base.metadata().catch(() => ({}));
    const w = Number(meta?.width || 0);
    const h = Number(meta?.height || 0);
    // Already small enough — skip the re-encode entirely.
    if (w > 0 && h > 0 && Math.max(w, h) <= maxEdgePx && buffer.length <= 200_000) {
      return buffer;
    }
    const out = await base
      .resize({
        width:              maxEdgePx,
        height:             maxEdgePx,
        fit:                "inside",
        withoutEnlargement: true,
      })
      .jpeg({ quality: 85 })
      .toBuffer();
    if (Buffer.isBuffer(out) && out.length > 1000) {
      console.log("📐 VISION DOWNSCALE", {
        rid:      rid || "",
        from:     buffer.length,
        to:       out.length,
        srcDim:   w && h ? `${w}x${h}` : "?",
        maxEdge:  maxEdgePx,
        savedPct: w && h ? Math.round((1 - out.length / buffer.length) * 100) : null,
      });
      return out;
    }
    return buffer;
  } catch (e) {
    console.warn("⚠️ VISION DOWNSCALE FAILED — using original", { rid: rid || "", err: e?.message });
    return buffer;
  }
}

async function analyzeImageQuality(buffer) {
  try {
    const sharp = await getSharp();
    const base = sharp(buffer, { failOn: "none" }).rotate();

    // Parallelize the three sharp operations — previously serial (metadata →
    // stats → greyscale-resize), now concurrent. stats() is the expensive one
    // (~200ms on a full image); running all three at once cuts this to ~200ms.
    const [metadata, stats, tiny] = await Promise.all([
      base.metadata().catch(() => ({})),
      base.stats().catch(() => null),
      base
        .clone()
        .greyscale()
        .resize({ width: 64, height: 64, fit: "inside", withoutEnlargement: true })
        .raw()
        .toBuffer({ resolveWithObject: true }),
    ]);

    const raw = tiny.data || Buffer.from([]);
    const width = Number(tiny.info?.width || 0);
    const height = Number(tiny.info?.height || 0);

    let edgeSum = 0;
    let edgeCount = 0;

    for (let y = 0; y < height - 1; y++) {
      for (let x = 0; x < width - 1; x++) {
        const idx = y * width + x;
        const rightIdx = idx + 1;
        const downIdx = idx + width;

        edgeSum += Math.abs(raw[idx] - raw[rightIdx]);
        edgeSum += Math.abs(raw[idx] - raw[downIdx]);
        edgeCount += 2;
      }
    }

    const detailScore = edgeCount
      ? Math.max(0, Math.min(1, edgeSum / edgeCount / 32))
      : 0;

    const brightnessScore = stats?.channels?.[0]?.mean
      ? Math.max(0, Math.min(1, stats.channels[0].mean / 255))
      : null;

    const contrastScore = stats?.channels?.[0]?.stdev
      ? Math.max(0, Math.min(1, stats.channels[0].stdev / 64))
      : null;

    const likelyBlurry = detailScore < 0.07;
    const likelyDark = brightnessScore != null && brightnessScore < 0.16;
    const lowContrast = contrastScore != null && contrastScore < 0.10;

    return {
      width: metadata?.width || null,
      height: metadata?.height || null,
      format: metadata?.format || null,
      detailScore: round2(detailScore),
      brightnessScore: brightnessScore == null ? null : round2(brightnessScore),
      contrastScore: contrastScore == null ? null : round2(contrastScore),
      likelyBlurry,
      likelyDark,
      lowContrast,
      usable: !(likelyBlurry || likelyDark),
    };
  } catch {
    return {
      width: null,
      height: null,
      format: null,
      detailScore: null,
      brightnessScore: null,
      contrastScore: null,
      likelyBlurry: false,
      likelyDark: false,
      lowContrast: false,
      usable: true,
    };
  }
}

async function writeBufferIfMissing(key, buffer) {
  const absPath = storagePathFromKey(key);
  await ensureDir(path.dirname(absPath));

  if (!(await fileExists(absPath))) {
    await fs.writeFile(absPath, buffer);
  }

  return absPath;
}

async function writeJson(key, value) {
  const absPath = storagePathFromKey(key);
  await ensureDir(path.dirname(absPath));
  await fs.writeFile(absPath, JSON.stringify(value, null, 2), "utf8");
  return absPath;
}

async function readJson(key) {
  const absPath = storagePathFromKey(key);

  try {
    const raw = await fs.readFile(absPath, "utf8");
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

async function preprocessScanUpload(file) {
  const originalBuffer = Buffer.isBuffer(file?.buffer) ? file.buffer : null;

  if (!originalBuffer || !originalBuffer.length) {
    throw new Error("missing_upload_buffer");
  }

  try {
    const sharp = await getSharp();
    const base = sharp(originalBuffer, { failOn: "none" }).rotate();

    // Parallelize main encode + thumbnail — previously serial (transformed then
    // thumb then quality). Now all three race concurrently; wall time = slowest
    // single operation instead of their sum.
    const [transformed, thumb, quality] = await Promise.all([
      base
        .clone()
        .resize({ width: PREPROCESS_MAX_EDGE, height: PREPROCESS_MAX_EDGE, fit: "inside", withoutEnlargement: true })
        .jpeg({ quality: PREPROCESS_JPEG_QUALITY })
        .toBuffer({ resolveWithObject: true }),
      base
        .clone()
        .resize({ width: PREPROCESS_THUMB_EDGE, height: PREPROCESS_THUMB_EDGE, fit: "inside", withoutEnlargement: true })
        .jpeg({ quality: 76 })
        .toBuffer({ resolveWithObject: true }),
      analyzeImageQuality(originalBuffer).catch(() => null),
    ]);

    return {
      buffer: transformed.data,
      mimetype: "image/jpeg",
      thumbnailBuffer: thumb.data,
      thumbnailMime: "image/jpeg",
      quality,
      metadata: {
        width: transformed.info?.width || null,
        height: transformed.info?.height || null,
        channels: transformed.info?.channels || null,
        size: transformed.data.length,
        originalSize: originalBuffer.length,
        transformed: true,
        thumbnailSize: thumb.data.length,
      },
    };
  } catch (err) {
    console.warn(
      "⚠️ preprocessScanUpload failed, using original buffer",
      err?.message || err
    );

    const quality = await analyzeImageQuality(originalBuffer).catch(() => null);

    return {
      buffer: originalBuffer,
      mimetype: file?.mimetype || "application/octet-stream",
      thumbnailBuffer: null,
      thumbnailMime: null,
      quality,
      metadata: {
        width: null,
        height: null,
        channels: null,
        size: originalBuffer.length,
        originalSize: originalBuffer.length,
        transformed: false,
        thumbnailSize: 0,
      },
    };
  }
}

async function persistScanArtifacts(file, imageHash) {
  await scanStorageReady;

  const originalExt = extensionFromMime(file?.mimetype || "");
  const originalKey = scanOriginalKey(imageHash, originalExt);
  const processedKey = scanProcessedKey(imageHash);
  const thumbKey = scanThumbKey(imageHash);
  const manifestKey = scanManifestKey(imageHash);

  const processed = await preprocessScanUpload(file);

  await Promise.all([
    objectStorePutBuffer(
      originalKey,
      file.buffer,
      file?.mimetype || "application/octet-stream",
      { imageHash, assetKind: "original" }
    ),
    objectStorePutBuffer(
      processedKey,
      processed.buffer,
      processed.mimetype,
      { imageHash, assetKind: "processed" }
    ),
    Buffer.isBuffer(processed.thumbnailBuffer) && processed.thumbnailBuffer.length
      ? objectStorePutBuffer(
          thumbKey,
          processed.thumbnailBuffer,
          processed.thumbnailMime || "image/jpeg",
          { imageHash, assetKind: "thumb" }
        )
      : Promise.resolve(),
  ]);

  const manifest = {
    hash: imageHash,
    createdAt: Date.now(),
    objectStoreProvider: canUseS3ObjectStore() ? "s3" : "local",
    original: {
      key: originalKey,
      url: objectStorePublicUrl(originalKey),
      mimetype: file?.mimetype || null,
      size: Buffer.isBuffer(file?.buffer) ? file.buffer.length : 0,
    },
    processed: {
      key: processedKey,
      url: objectStorePublicUrl(processedKey),
      mimetype: processed.mimetype,
      size: processed.metadata?.size || processed.buffer.length,
      width: processed.metadata?.width || null,
      height: processed.metadata?.height || null,
      transformed: !!processed.metadata?.transformed,
    },
    thumbnail: {
      key:
        Buffer.isBuffer(processed.thumbnailBuffer) && processed.thumbnailBuffer.length
          ? thumbKey
          : null,
      url:
        Buffer.isBuffer(processed.thumbnailBuffer) && processed.thumbnailBuffer.length
          ? objectStorePublicUrl(thumbKey)
          : null,
      size: processed.metadata?.thumbnailSize || 0,
    },
    quality: processed.quality || null,
  };

  await writeJson(manifestKey, manifest);

  return {
    imageHash,
    asset: {
      hash: imageHash,
      originalKey,
      processedKey,
      thumbKey:
        Buffer.isBuffer(processed.thumbnailBuffer) && processed.thumbnailBuffer.length
          ? thumbKey
          : null,
      manifestKey,
      originalUrl: objectStorePublicUrl(originalKey),
      processedUrl: objectStorePublicUrl(processedKey),
      thumbUrl:
        Buffer.isBuffer(processed.thumbnailBuffer) && processed.thumbnailBuffer.length
          ? objectStorePublicUrl(thumbKey)
          : null,
    },
    preprocess: {
      ...processed.metadata,
      quality: processed.quality || null,
    },
    processedBuffer: processed.buffer,
    processedMime: processed.mimetype,
  };
}

async function loadStoredEmbedding(imageHash) {
  if (!imageHash) return null;

  const redisKey = `scan_embedding:${imageHash}`;

  try {
    const cached = await cacheGet(redisKey);
    if (Array.isArray(cached?.vector) && cached.vector.length) {
      return cached.vector;
    }
  } catch {}

  const disk = await readJson(scanEmbeddingKey(imageHash));
  const vector = Array.isArray(disk?.vector) ? disk.vector : null;

  if (vector?.length) {
    try {
      await cacheSet(redisKey, { vector }, 7 * 24 * 60 * 60);
    } catch {}
    return vector;
  }

  return null;
}

async function saveStoredEmbedding(imageHash, vector) {
  if (!imageHash || !Array.isArray(vector) || !vector.length) return;

  const payload = {
    hash: imageHash,
    createdAt: Date.now(),
    dims: vector.length,
    vector,
  };

  await writeJson(scanEmbeddingKey(imageHash), payload);

  try {
    await cacheSet(`scan_embedding:${imageHash}`, { vector }, 7 * 24 * 60 * 60);
  } catch {}
}

async function getOrCreateStoredEmbedding(imageHash, buffer) {
  const existing = await loadStoredEmbedding(imageHash);
  if (existing?.length) return existing;

  if (!Buffer.isBuffer(buffer) || !buffer.length) return null;

  const vector = await computeImageEmbedding(buffer);

  if (Array.isArray(vector) && vector.length) {
    await saveStoredEmbedding(imageHash, vector);
    return vector;
  }

  return null;
}

// -------------------- Tiny utils --------------------
function withTimeout(ms) {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), ms);
  return { signal: controller.signal, cancel: () => clearTimeout(id) };
}

function withHardTimeout(promise, ms, label = "timeout") {
  let id;

  const killer = new Promise((_, reject) => {
    id = setTimeout(() => {
      const err = new Error(label);
      err.name = "AbortError";
      reject(err);
    }, ms);
  });

  return Promise.race([promise, killer]).finally(() => {
    clearTimeout(id);
  });
}

function clamp01(n) {
  return Math.max(0, Math.min(1, n));
}

// Phase 2 boundary helper: outbound API responses must emit canonical
// verdicts only. enforceVerdictOnPayload throws on drift (loud, by
// design); at the user-facing edge we don't want a single bad cached
// payload to crash the response — we want to drop the verdict, log,
// and let the rest of the intel ship. Phase 6 wires telemetry here.
function safeEnforceVerdict(payload, source) {
  try {
    return enforceVerdictOnPayload(payload, source);
  } catch (e) {
    if (e instanceof VerdictLeakError) {
      console.warn(`[verdict-leak] ${source}: dropped payload —`, e.message);
      return null;
    }
    throw e;
  }
}

function safeStr(s, max = 180) {
  if (typeof s !== "string") return "";
  const t = s.trim();
  return t.length > max ? t.slice(0, max) : t;
}

function normalizeQuery(q = "") {
  return String(q)
    .toLowerCase()
    // keep "used", "pre owned", "marketplace" because they are useful intent
    .replace(/\b(cheap|deal|best price|sale)\b/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

// -----------------------------------
// QUERY VARIANT ENGINE (Evan AI Brain)
// -----------------------------------
function buildQueryVariants(query = "") {
  const q = normalizeQuery(query);

  const variants = new Set();
  variants.add(q);

  // eyewear intelligence
  if (q.includes("orange")) {
    variants.add("orange lens glasses");
    variants.add("amber lens glasses");
    variants.add("orange blue light glasses");
  }

  if (q.includes("blue light")) {
    variants.add("gaming glasses");
    variants.add("computer glasses");
  }

  if (q.includes("wrap")) {
    variants.add("wraparound glasses");
    variants.add("sports glasses");
  }

  if (q.includes("glasses")) {
    variants.add(q.replace("glasses", "eyewear"));
  }

  return Array.from(variants).slice(0, 5);
}

// =====================================================
// SAFE FALLBACK MEMORY
// NOTE:
// Do NOT persist last-good scan identity globally across requests.
// That can leak one item's identity into a later unrelated scan.
// =====================================================
let LAST_GOOD_QUERY = null;
let LAST_GOOD_CATEGORY = null;

function rememberGoodQuery(_q) {
  // intentionally disabled to prevent cross-scan bleed
  return;
}

// isGarbageQuery and isGenericGarbageQuery are imported from ./src/queryGuards.js

// Phase A2.6: Checks if a query is usable as a seed for vision recovery.
// Stricter than just "not garbage" — requires at least 3 words and a letter.
function isUsableVisionQuery(query) {
  if (!query || typeof query !== "string") return false;
  const trimmed = query.trim();
  if (!trimmed || isGarbageQuery(trimmed)) return false;
  if (trimmed.split(/\s+/).length < 3) return false;
  if (!/[a-zA-Z]/.test(trimmed)) return false;
  return true;
}

// ── Phase 2C.6: stronger generic-query detector ───────────────────────────────
// isGarbageQuery only catches single-word literal junk ("item", "product",
// "thing"). It cannot catch multi-word vague phrases like "item for",
// "economy item for", "toy item", "model toy", "thing for sale". A real
// scan that emitted "item for" was fanned out to SerpAPI and produced 40
// unrelated results (Bluey toys, baby gear, etc.); a result-aware refresh
// then mutated the query into "item bluey" since eBay's first hit was a
// Bluey product. We need a stricter guard at the market-search entry.
//
// Rules:
//   1. Anything isGarbageQuery rejects → reject here too.
//   2. Tokenize. A token is "meaningful" iff it has ≥2 chars AND is not
//      in the GENERIC_TOKEN_SET (which lists adjectives/prepositions/
//      filler nouns that contribute zero search specificity).
//   3. A token with a digit+letter mix ("787-9" → "7879", "rb3025",
//      "yz450f", "next2") counts as a STRONG SIGNAL — SKU/model codes
//      are evidence even when alone.
//   4. Pass iff (hasStrongSignal) OR (meaningfulCount >= 2).
//   5. Otherwise reject as generic.
//
// Examples that REJECT: "item for", "economy item for", "toy", "model",
// "product object", "thing for sale", "stuff", "economy item".
// Examples that PASS: "Hawaiian Airlines Boeing 787-9 model airplane"
// (strong signal "787-9"), "Air Jordan 1 Low OG Year of the Rabbit"
// (many meaningful tokens), "iPhone 13" (two meaningful tokens).
const GENERIC_TOKEN_SET = new Set([
  // Filler nouns
  "item", "items", "object", "objects", "product", "products",
  "thing", "things", "stuff", "goods", "merchandise", "wares",
  "piece", "pieces", "model", "models", "unit", "units",
  "toy", "toys", "set", "kit", "pack", "bundle",
  // Adjectives that add no specificity
  "economy", "basic", "standard", "generic", "plain", "simple",
  "regular", "ordinary", "common", "general", "misc", "miscellaneous",
  "unknown", "untitled", "various", "assorted",
  // Prepositions / conjunctions / articles
  "for", "of", "the", "an", "with", "without", "and", "or",
  "to", "from", "in", "on", "at", "by",
  // Condition / commerce filler
  "new", "used", "good", "best", "cheap", "tier", "grade",
  "sale", "listing", "consumer", "resale", "online", "value",
  // Low-specificity catch-alls
  "type", "kind", "style", "form", "version",
]);

function isGenericVisionQuery(q) {
  const raw = String(q || "").trim();
  if (!raw) return true;
  const lower = raw.toLowerCase();
  if (isGarbageQuery(lower)) return true;

  const rawTokens = lower.split(/\s+/).filter(Boolean);
  if (rawTokens.length === 0) return true;

  let meaningful = 0;
  let hasStrongSignal = false;
  for (const tok of rawTokens) {
    const clean = tok.replace(/[^a-z0-9]/g, "");
    if (clean.length < 2) continue;

    // Strong signal: SKU / model-code style (digits + letters).
    if (/\d/.test(clean) && /[a-z]/.test(clean)) {
      hasStrongSignal = true;
      meaningful++;
      continue;
    }

    // Generic word → not meaningful.
    if (GENERIC_TOKEN_SET.has(clean)) continue;

    meaningful++;
  }

  if (hasStrongSignal) return false;
  if (meaningful < 2) return true;
  return false;
}

// ── Phase 2C.6: identity-driven query recovery ────────────────────────────────
// When the inbound query is generic, before we either search marketplaces
// (which will produce garbage) or hard-block, try to recover a usable query
// from the visionIdentity payload the client sent. Each strategy is checked
// in order; the first to produce a non-generic query wins. Returns either
// { query, source } or null if every strategy fails. The "source" string
// goes into the VISION_QUERY_REPAIRED log so we can see which lane caught
// the recovery in production.
function recoverQueryFromIdentity(identity, currentQuery, category, variants) {
  const tryQuery = (raw) => {
    const norm = normalizeQuery(raw || "");
    if (!norm) return null;
    if (isGenericVisionQuery(norm)) return null;
    return norm;
  };

  // 1. Vision's own canonical query.
  let candidate = tryQuery(identity && identity.exactQuery);
  if (candidate) return { query: candidate, source: "identity_exactQuery" };

  // 2. Vision-suggested search queries (ranked array).
  if (identity && Array.isArray(identity.searchQueries)) {
    for (const sq of identity.searchQueries) {
      candidate = tryQuery(sq);
      if (candidate) return { query: candidate, source: "identity_searchQueries" };
    }
  }

  // 3. Brand + model synthesis (e.g. "Hawaiian Airlines 787-9").
  if (identity && identity.brand && identity.model) {
    candidate = tryQuery(`${identity.brand} ${identity.model}`);
    if (candidate) return { query: candidate, source: "identity_brand_model" };
  }

  // 4. Brand + category synthesis.
  if (identity && identity.brand && (identity.category || category)) {
    candidate = tryQuery(`${identity.brand} ${identity.category || category}`);
    if (candidate) return { query: candidate, source: "identity_brand_category" };
  }

  // 5. Category-specific seed. Aircraft / model-airplane scans get an
  //    explicit "model airplane" seed plus any airline / scale hint, so
  //    a Hawaiian Airlines 787 scan doesn't fan out as "item for" even
  //    when vision returned nothing structured.
  const catRaw = String((identity && identity.category) || category || "").toLowerCase();
  const queryRaw = String(currentQuery || "").toLowerCase();
  const looksAircraft =
    /aircraft|airplane|airline|aviation|boeing|airbus|jet/i.test(catRaw) ||
    /aircraft|airplane|airline|aviation|boeing|airbus|jet/i.test(queryRaw);
  if (looksAircraft) {
    const airlineHint = (identity && (identity.airline || identity.subBrand)) || "";
    const scaleHint   = (identity && identity.scale) || "";
    const seedParts   = ["model airplane", "diecast", airlineHint, scaleHint]
      .filter((s) => s && String(s).trim().length > 0);
    candidate = tryQuery(seedParts.join(" "));
    if (candidate) return { query: candidate, source: "category_aircraft_seed" };
  }

  // 6. Inbound variants[] (client sometimes ships specific phrasing here).
  if (Array.isArray(variants)) {
    for (const v of variants) {
      candidate = tryQuery(v);
      if (candidate) return { query: candidate, source: "variants" };
    }
  }

  return null;
}

function inferVisionCategory(q) {
  const s = String(q || "").toLowerCase();

  // eyewear
  if (
    s.includes("glasses") ||
    s.includes("eyewear") ||
    s.includes("sunglasses") ||
    s.includes("frames") ||
    s.includes("eyeglass")
  ) return "eyewear";

  // headwear
  if (
    s.includes("hat") ||
    s.includes("cap") ||
    s.includes("snapback") ||
    s.includes("beanie")
  ) return "headwear";

  // footwear
  if (
    s.includes("shoe") ||
    s.includes("sneaker") ||
    s.includes("boot") ||
    s.includes("loafer") ||
    s.includes("heel") ||
    s.includes("trainer")
  ) return "footwear";

  // bags
  if (
    s.includes("bag") ||
    s.includes("backpack") ||
    s.includes("rucksack") ||
    s.includes("tote") ||
    s.includes("handbag") ||
    s.includes("purse")
  ) return "bags";

  // clothing
  if (
    s.includes("shirt") ||
    s.includes("hoodie") ||
    s.includes("jacket") ||
    s.includes("coat") ||
    s.includes("pants") ||
    s.includes("jeans") ||
    s.includes("shorts") ||
    s.includes("sweater")
  ) return "apparel";

  // electronics
  if (
    s.includes("headphones") ||
    s.includes("earbuds") ||
    s.includes("speaker") ||
    s.includes("monitor") ||
    s.includes("keyboard") ||
    s.includes("mouse")
  ) return "electronics";

  // watches
  if (
    s.includes("watch") ||
    s.includes("wristwatch")
  ) return "watch";

  return null;
}

function categoryFallback(category) {
  const map = {
    eyewear: "sunglasses frames",
    headwear: "hat cap used",
    footwear: "sneakers shoes used",
    electronics: "used electronics device",
    apparel: "used clothing",
    watches: "used watch timepiece",
    jewelry: "used jewelry",
    bags: "used bag handbag",
    toys: "used toy collectible",
    books: "used book",
    furniture: "used furniture",
    tools: "used tools hardware",
    sports: "used sports equipment",
    music: "used instrument",
    art: "art print collectible",
    games: "used video game",
    automotive: "used auto part accessory",
    collectibles: "vintage collectible item",
    home: "used home decor",
  };
  return map[category] || null;
}

function isWeakGenericVisionQuery(q, mode = "item") {
  if (mode !== "item") return false;

  const s = normalizeQuery(q || "");
  if (!s) return true;

  return new Set([
    "item",
    "object",
    "product",
    "thing",
    "consumer product",
    "glasses",
    "eyewear",
    "frames",
    "sunglasses",
    "hat",
    "shoes",
    "clothing",
    "electronics",
  ]).has(s);
}

function stabilizeVisionQuery(rawQuery, normalizedQuery, mode = "item") {
  if (mode !== "item") return normalizedQuery || rawQuery || null;

  const raw = normalizeQuery(rawQuery || "");
  const norm = normalizeQuery(normalizedQuery || "");

  if (raw && !isWeakGenericVisionQuery(raw, mode)) {
    if (!norm || isWeakGenericVisionQuery(norm, mode)) {
      return rawQuery;
    }
  }

  return normalizedQuery || rawQuery || null;
}

function normalizeVisionQuery(query, mode = "item") {
  if (mode !== "item") return query;

  const raw = normalizeQuery(query || "");
  if (!raw) return null;

  const q = raw;

  const hasBlue =
    q.includes("blue light") ||
    q.includes("blue-light") ||
    q.includes("computer glasses") ||
    q.includes("computer") ||
    q.includes("screen") ||
    q.includes("anti blue") ||
    q.includes("blue blocker") ||
    q.includes("block blue") ||
    q.includes("gaming glasses");

  const hasOrange =
    q.includes("orange") ||
    q.includes("amber") ||
    q.includes("yellow tint") ||
    q.includes("yellow lens") ||
    q.includes("amber lens") ||
    q.includes("orange lens");

  const hasClear =
    q.includes("clear") ||
    q.includes("clear lens");

  const hasSun =
    q.includes("sunglass") ||
    q.includes("shade") ||
    q.includes("shades") ||
    q.includes("uv") ||
    q.includes("uv400") ||
    q.includes("polarized") ||
    q.includes("sun ");

  const hasGlasses =
    q.includes("glasses") ||
    q.includes("eyewear") ||
    q.includes("frames") ||
    q.includes("spectacles") ||
    q.includes("eyeglass");

  const hasLensWord =
    q.includes("lens") ||
    q.includes("lenses") ||
    q.includes("tinted") ||
    q.includes("tint");

  const frameColor =
    q.includes("black") ? "black" :
    q.includes("brown") ? "brown" :
    q.includes("white") ? "white" :
    q.includes("clear frame") || q.includes("transparent frame") ? "clear frame" :
    q.includes("tortoise") || q.includes("tortoiseshell") ? "tortoise" :
    null;

  const descriptors = [];

  if (
    q.includes("oversized") ||
    q.includes("large frame") ||
    q.includes("big frame")
  ) {
    descriptors.push("oversized");
  }

  if (q.includes("oval")) descriptors.push("oval");
  if (q.includes("wrap")) descriptors.push("wraparound");
  if (q.includes("shield")) descriptors.push("shield");
  if (q.includes("aviator")) descriptors.push("aviator");
  if (q.includes("rectangle")) descriptors.push("rectangle");
  if (q.includes("round")) descriptors.push("round");
  if (q.includes("square")) descriptors.push("square");
  if (q.includes("wire")) descriptors.push("wire frame");
  if (q.includes("rimless")) descriptors.push("rimless");

  const stylePrefix = [frameColor, ...descriptors]
    .filter(Boolean)
    .join(" ")
    .replace(/\s+/g, " ")
    .trim();

  let candidate = raw;

  if (hasOrange && hasBlue) {
    const base = hasLensWord
      ? "orange lens blue light glasses"
      : "orange blue light glasses";
    candidate = [stylePrefix, base].filter(Boolean).join(" ").replace(/\s+/g, " ").trim();
  } else if (hasBlue) {
    candidate = [stylePrefix, "blue light glasses"]
      .filter(Boolean)
      .join(" ")
      .replace(/\s+/g, " ")
      .trim();
  } else if (hasSun) {
    if (hasOrange) {
      const base = hasLensWord ? "orange lens sunglasses" : "orange sunglasses";
      candidate = [stylePrefix, base].filter(Boolean).join(" ").replace(/\s+/g, " ").trim();
    } else {
      candidate = [stylePrefix, "sunglasses"]
        .filter(Boolean)
        .join(" ")
        .replace(/\s+/g, " ")
        .trim();
    }
  } else if (hasClear) {
    candidate = [stylePrefix, "clear lens glasses"]
      .filter(Boolean)
      .join(" ")
      .replace(/\s+/g, " ")
      .trim();
  } else if (hasOrange) {
    const base = hasLensWord ? "orange lens glasses" : "orange glasses";
    candidate = [stylePrefix, base].filter(Boolean).join(" ").replace(/\s+/g, " ").trim();
  } else if (hasGlasses) {
    candidate = [stylePrefix, "glasses"]
      .filter(Boolean)
      .join(" ")
      .replace(/\s+/g, " ")
      .trim();
  }

  // CRITICAL:
  // if normalization drops informative tokens (brand/model/detail),
  // keep the richer original query instead of flattening it.
  const rawTokens = titleTokens(raw);
  const candidateTokens = titleTokens(candidate);
  const candidateSet = new Set(candidateTokens);
  const droppedTokens = rawTokens.filter((tok) => !candidateSet.has(tok));

  const rawLooksDetailed = rawTokens.length >= 4;
  const candidateIsBroader = candidateTokens.length < rawTokens.length;

  if (
    candidate &&
    candidate !== raw &&
    rawLooksDetailed &&
    candidateIsBroader &&
    droppedTokens.length >= 1
  ) {
    return raw;
  }

  return candidate || raw;
}

function sha256(buf) {
  return crypto.createHash("sha256").update(buf).digest("hex");
}

function resaleScore(items) {
  if (!items.length) return 0;
  const prices = items.map(i => i.price).filter((n) => typeof n === "number" && Number.isFinite(n));
  if (!prices.length) return 0;

  const spread = Math.max(...prices) - Math.min(...prices);
  const avg = prices.reduce((a,b)=>a+b,0)/prices.length;

  return spread / Math.max(avg, 1);
}

// -------------------- HUMAN INTUITION PRICING --------------------
function median(sorted) {
  const n = sorted.length;
  if (!n) return null;
  const mid = Math.floor(n / 2);
  return n % 2 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}

function quantile(sorted, q) {
  const n = sorted.length;
  if (!n) return null;
  const pos = (n - 1) * q;
  const base = Math.floor(pos);
  const rest = pos - base;
  const a = sorted[base];
  const b = sorted[Math.min(base + 1, n - 1)];
  return a + (b - a) * rest;
}

// Returns: typicalLow/High (human range), dealScore (0-1), weirdness flag
function computeMarketIntuition(items, payingPrice = null) {
  const prices = (items || [])
    .map((i) => i?.totalPrice ?? i?.price)
    .filter((n) => typeof n === "number" && Number.isFinite(n) && n > 0)
    .sort((a, b) => a - b);

  if (prices.length < 4) {
    return {
      median: prices.length ? prices[Math.floor(prices.length / 2)] : null,
      typicalLow: prices[0] ?? null,
      typicalHigh: prices[prices.length - 1] ?? null,
      dealScore: null,
      isWeirdPrice: false,
      reason: "not_enough_data",
    };
  }

  const q1 = quantile(prices, 0.25);
  const q3 = quantile(prices, 0.75);
  const med = median(prices);

  const iqr = Math.max((q3 ?? 0) - (q1 ?? 0), 0.01);
  const lowFence = (q1 ?? 0) - 1.5 * iqr;
  const highFence = (q3 ?? 0) + 1.5 * iqr;

  // Human “typical range” = clamp within fences
  const typical = prices.filter((p) => p >= lowFence && p <= highFence);
  const typicalLow = typical[0] ?? prices[0];
  const typicalHigh = typical[typical.length - 1] ?? prices[prices.length - 1];

  let dealScore = null;
  let isWeirdPrice = false;

  if (
    typeof payingPrice === "number" &&
    Number.isFinite(payingPrice) &&
    payingPrice > 0
  ) {
    // 1.0 = insanely good (bottom of typical), 0.0 = bad (above typicalHigh)
    const denom = Math.max(typicalHigh - typicalLow, 0.01);
    dealScore = 1 - (payingPrice - typicalLow) / denom;
    dealScore = clamp01(dealScore);

    isWeirdPrice =
      payingPrice < typicalLow * 0.55 ||
      payingPrice > typicalHigh * 1.8;
  }

  return {
    median: med,
    typicalLow,
    typicalHigh,
    dealScore,
    isWeirdPrice,
    reason: "ok",
  };
}

// -------------------- HUMAN DEAL VERDICT ENGINE --------------------
// dealEngineVerdict: BUY / PASS / CHECK (spec-aligned two-phase system)
function buildLocalDealVerdict(intuition, visionConfidence = 0.5) {
  if (!intuition || intuition.reason !== "ok") {
    return {
      label: "UNKNOWN",
      emoji: "🤔",
      dealEngineVerdict: "CHECK",
      confidence: 0.35,
      reason: "Not enough market data yet",
    };
  }

  const score = intuition.dealScore;
  const weird = intuition.isWeirdPrice;

  const confidence = clamp01(
    (typeof score === "number" ? score : 0.5) * 0.65 +
      visionConfidence * 0.35
  );

  if (weird) {
    return {
      label: "RISKY",
      emoji: "⚠️",
      dealEngineVerdict: "PASS",
      confidence,
      reason: "Price sits outside normal market range",
    };
  }

  if (score >= 0.82) {
    return {
      label: "STEAL",
      emoji: "🔥",
      dealEngineVerdict: "BUY",
      confidence,
      reason: "Far below typical market pricing",
    };
  }

  if (score >= 0.62) {
    return {
      label: "GOOD DEAL",
      emoji: "🟢",
      dealEngineVerdict: "BUY",
      confidence,
      reason: "Below average market value",
    };
  }

  if (score >= 0.40) {
    return {
      label: "FAIR",
      emoji: "👌",
      dealEngineVerdict: "CHECK",
      confidence,
      reason: "Within normal market range",
    };
  }

  return {
    label: "OVERPRICED",
    emoji: "💸",
    dealEngineVerdict: "PASS",
    confidence,
    reason: "Above typical market pricing",
  };
}

