async function runBudgetedSourceLane(
  source,
  runner,
  { plan = "free", costUnits = 1 } = {}
) {
  const allowed = await sourceBudget.canUse(source, { plan, costUnits });

  if (!allowed) {
    incMetric("source_budget_block_total", 1, {
      source,
      plan,
    });

    logEvent("warn", "source_budget_blocked", {
      source,
      plan,
      costUnits,
    });

    return [];
  }

  await sourceBudget.note(source, { costUnits });

  try {
    const out = await runner();
    return Array.isArray(out) ? out : [];
  } catch (err) {
    logEvent("warn", "source_lane_failed", {
      source,
      plan,
      error: err?.message || String(err),
    });
    return [];
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// Phase 2C.8 — Per-scan SerpAPI budget
// ═══════════════════════════════════════════════════════════════════════════════
//
// Hard cap: ONE paid SerpAPI call per uncached scan. Cached scans use zero.
// The order is critical:
//   1. Vision builds the best query it can.
//   2. Routes check existing SERP_CACHE / internal cache (zero-cost, always
//      allowed regardless of budget).
//   3. If cache misses, the route consumes its single SerpAPI unit.
//   4. All correctness work (identity locks, merch rejection, sneaker / Jordan
//      filters, generic-query guard, clean-retrieval-pool check, verdict math)
//      runs locally on that one returned pool.
//   5. Any extra SerpAPI call after the first is blocked with a structured
//      SERP_BUDGET_BLOCKED log, unless DEV_BYPASS_SERP_BUDGET is set.
//
// The budget context is threaded through the request via AsyncLocalStorage
// so leaf functions (serpShopping / serpAmazon / serpScopedSearch / result-
// aware refresh / direct URL recovery) can consult it without changing every
// signature in the dispatch graph.
const SERP_BUDGET_STORE = new AsyncLocalStorage();
const SERP_BUDGET_MAX = Number(process.env.SERP_BUDGET_PER_SCAN || 1);
const SERP_BUDGET_TTL_MS = 10 * 60 * 1000; // 10 min per-scan eviction
const SERP_BUDGET_DEV_BYPASS = String(process.env.DEV_BYPASS_SERP_BUDGET || "").trim() === "1";

// Cross-route reuse: when /market/search/stream computes a result pool, store
// it here keyed by scanId / imageHash / normalizedQuery+userId so a subsequent
// /market/search for the SAME scan returns the same pool without re-billing.
// Stream + regular calls cannot double-bill the same scan.
const MARKET_SCAN_RESULT_CACHE = new Map();
const MARKET_SCAN_RESULT_TTL_MS = 5 * 60 * 1000; // 5 min

function _makeBudgetKey({ scanId, imageHash, query, userId }) {
  if (scanId) return `scan:${scanId}`;
  if (imageHash) return `img:${imageHash}`;
  const q = String(query || "").trim().toLowerCase().replace(/\s+/g, " ").slice(0, 120);
  const u = String(userId || "anon").slice(0, 48);
  return `q:${q}|${u}`;
}

// Map keyed by budget-key → { consumed, ts, route, query, scanId, history[] }.
const _SERP_BUDGET_REGISTRY = new Map();

function _evictStaleBudgetEntries(now) {
  for (const [k, entry] of _SERP_BUDGET_REGISTRY) {
    if (now - entry.ts > SERP_BUDGET_TTL_MS) _SERP_BUDGET_REGISTRY.delete(k);
  }
  for (const [k, entry] of MARKET_SCAN_RESULT_CACHE) {
    if (now - entry.ts > MARKET_SCAN_RESULT_TTL_MS) MARKET_SCAN_RESULT_CACHE.delete(k);
  }
}

/**
 * Public helper — return the current scan's budget context, or null when
 * called outside any request (e.g. background jobs, internal scripts). When
 * null, all SerpAPI calls bypass the budget (legacy behavior preserved).
 */
function getCurrentSerpBudgetCtx() {
  return SERP_BUDGET_STORE.getStore() || null;
}

/**
 * Public helper — check whether a SerpAPI call can be issued under the
 * current request's budget. Cheap, no side effects. Returns true when no
 * budget context exists (legacy caller).
 */
function canUseSerpBudget(ctx = null) {
  if (SERP_BUDGET_DEV_BYPASS) return true;
  const c = ctx || getCurrentSerpBudgetCtx();
  if (!c) return true; // no context = bypass (back-compat)
  const key = c.key;
  const entry = _SERP_BUDGET_REGISTRY.get(key);
  if (!entry) return true;
  return entry.consumed < (c.max || SERP_BUDGET_MAX);
}

/**
 * Phase 2C.9 — primary-source priority enforcement.
 *
 * The single allowed-primary SerpAPI lane is serpShopping (google_shopping
 * engine). serpAmazon, serpScopedSearch (Poshmark / Mercari / etc.), and
 * direct URL recovery via google_product are NEVER allowed to consume the
 * one paid unit when a route-level scan context exists — they can only run
 * as legacy fallbacks (no context, e.g. background scripts) or when a
 * route opts in with `ctx.allowNonShoppingPrimary = true`.
 *
 * This fixes the live-log race where the parallel Tier B fanout had
 * serpAmazon win the consume coin-flip first, blocking the better-fit
 * google_shopping query for the rest of the scan.
 */
const SERP_PRIMARY_REASONS = new Set(["serpShopping"]);

/**
 * Public helper — atomically attempt to consume one SerpAPI unit on the
 * current scan's budget. Returns true on success, false on refusal (and
 * logs SERP_BUDGET_BLOCKED with the offending route / query). Cache layers
 * MUST NOT call this — only paid network call sites.
 */
function consumeSerpBudget(reason, callDescriptor = {}) {
  const c = getCurrentSerpBudgetCtx();
  if (!c) return true; // no context = bypass

  // Phase 2C.9: route-level priority gate. serpShopping is the only allowed
  // primary source unless the route explicitly opted into Amazon-primary.
  if (!SERP_PRIMARY_REASONS.has(reason) && !c.allowNonShoppingPrimary) {
    c.blockedExtraCalls = (c.blockedExtraCalls || 0) + 1;
    console.warn("SERP_BUDGET_BLOCKED", {
      scanId: c.scanId,
      route: c.route,
      query: callDescriptor.query || c.query,
      reason,
      reasonForBlock: "non_primary_source_blocked_by_priority",
      primaryReserved: "serpShopping",
      ...callDescriptor,
    });
    return false;
  }
  if (SERP_BUDGET_DEV_BYPASS) {
    // Still account in summary so logs are accurate, but do not block.
    const entry = _SERP_BUDGET_REGISTRY.get(c.key) || {
      consumed: 0, ts: Date.now(), route: c.route, query: c.query, scanId: c.scanId, history: [],
    };
    entry.consumed += 1;
    entry.ts = Date.now();
    entry.history.push({ reason, ts: Date.now(), bypassed: true, ...callDescriptor });
    _SERP_BUDGET_REGISTRY.set(c.key, entry);
    c.callsUsed = (c.callsUsed || 0) + 1;
    console.log("SERP_BUDGET_CONSUMED", {
      scanId: c.scanId, route: c.route, reason, consumed: entry.consumed,
      max: c.max || SERP_BUDGET_MAX, devBypass: true, ...callDescriptor,
    });
    return true;
  }
  const max = c.max || SERP_BUDGET_MAX;
  const existing = _SERP_BUDGET_REGISTRY.get(c.key);
  const current = existing?.consumed || 0;
  if (current >= max) {
    c.blockedExtraCalls = (c.blockedExtraCalls || 0) + 1;
    console.warn("SERP_BUDGET_BLOCKED", {
      scanId: c.scanId,
      route: c.route,
      query: callDescriptor.query || c.query,
      reason,
      alreadyConsumedBy: existing?.history?.[0]?.reason || null,
      alreadyConsumedQuery: existing?.history?.[0]?.query || existing?.query || null,
      consumed: current,
      max,
    });
    return false;
  }
  const entry = existing || {
    consumed: 0, ts: Date.now(), route: c.route, query: c.query, scanId: c.scanId, history: [],
  };
  entry.consumed += 1;
  entry.ts = Date.now();
  entry.history.push({ reason, ts: Date.now(), ...callDescriptor });
  _SERP_BUDGET_REGISTRY.set(c.key, entry);
  c.callsUsed = (c.callsUsed || 0) + 1;
  console.log("SERP_BUDGET_CONSUMED", {
    scanId: c.scanId, route: c.route, reason, consumed: entry.consumed, max, ...callDescriptor,
  });
  return true;
}

/**
 * Public helper — current budget status for the active scan (or a passed
 * ctx). Read-only.
 */
function getSerpBudgetStatus(ctx = null) {
  const c = ctx || getCurrentSerpBudgetCtx();
  if (!c) return { key: null, consumed: 0, max: SERP_BUDGET_MAX, available: SERP_BUDGET_MAX, devBypass: SERP_BUDGET_DEV_BYPASS };
  const entry = _SERP_BUDGET_REGISTRY.get(c.key);
  const consumed = entry?.consumed || 0;
  const max = c.max || SERP_BUDGET_MAX;
  return {
    key: c.key,
    consumed,
    max,
    available: Math.max(0, max - consumed),
    devBypass: SERP_BUDGET_DEV_BYPASS,
    history: entry?.history || [],
  };
}

/**
 * Public helper — wrap a route handler body so all nested SerpAPI calls
 * see the same budget context. Builds the canonical key from scanId /
 * imageHash / query+user. Returns the result of `fn()`.
 */
function withSerpBudget(ctxSeed, fn) {
  _evictStaleBudgetEntries(Date.now());
  const ctx = {
    scanId: ctxSeed.scanId || null,
    imageHash: ctxSeed.imageHash || null,
    query: ctxSeed.query || null,
    userId: ctxSeed.userId || null,
    route: ctxSeed.route || null,
    max: ctxSeed.max || SERP_BUDGET_MAX,
    callsUsed: 0,
    blockedExtraCalls: 0,
    cacheHit: false,
    key: _makeBudgetKey(ctxSeed),
  };
  return SERP_BUDGET_STORE.run(ctx, () => fn(ctx));
}

/**
 * Public helper — emit a one-line audit summary at the end of a route.
 * Always call this so production logs have a single grep target per scan.
 */
function emitSerpBudgetSummary(finalItemCount = null) {
  const c = getCurrentSerpBudgetCtx();
  if (!c) return;
  const status = getSerpBudgetStatus(c);
  console.log("SERP_BUDGET_SUMMARY", {
    scanId: c.scanId,
    normalizedQuery: String(c.query || "").toLowerCase().slice(0, 120),
    route: c.route,
    serpCallsUsed: status.consumed,
    maxAllowed: status.max,
    cacheHit: !!c.cacheHit,
    blockedExtraCalls: c.blockedExtraCalls || 0,
    finalItemCount,
    devBypass: status.devBypass,
  });
}

/**
 * MARKET_SCAN_RESULT_CACHE helpers — short-lived cross-route cache. When
 * /market/search/stream finishes a search, it stores the payload here so
 * follow-up /market/search calls for the SAME scan return the same pool
 * without firing SerpAPI again.
 *
 * Phase 2C.10 — multi-key lookup AND multi-key store. A single scan's
 * payload is now indexed under every identity it has (scanId, imageHash,
 * normalized base query+user). Follow-up calls (enriched / brand-refined /
 * collector / vision-enrich-driven queries) may arrive with a DIFFERENT
 * query than the one that produced the original result, but they still
 * carry the same scanId or imageHash. Any one matching = cache hit.
 *
 * This fixes the production leak where:
 *   • stream stored under "scan:c.xxx"
 *   • follow-up /market/search seeded the lookup with only an enriched
 *     query (e.g. "geminijets ..."), missing the scan key, firing a new
 *     paid call even though the scan's result pool already existed.
 */
function _makeAllBudgetKeys(ctxSeed) {
  const keys = [];
  if (ctxSeed.scanId) keys.push(`scan:${ctxSeed.scanId}`);
  if (ctxSeed.imageHash) keys.push(`img:${ctxSeed.imageHash}`);
  const q = String(ctxSeed.query || "").trim().toLowerCase().replace(/\s+/g, " ").slice(0, 120);
  const u = String(ctxSeed.userId || "anon").slice(0, 48);
  if (q) keys.push(`q:${q}|${u}`);
  return keys;
}

function getMarketScanResult(ctxSeed) {
  _evictStaleBudgetEntries(Date.now());
  const candidateKeys = _makeAllBudgetKeys(ctxSeed);
  for (const key of candidateKeys) {
    const entry = MARKET_SCAN_RESULT_CACHE.get(key);
    if (!entry) continue;
    if (Date.now() - entry.ts > MARKET_SCAN_RESULT_TTL_MS) {
      MARKET_SCAN_RESULT_CACHE.delete(key);
      continue;
    }
    return { ...entry, hitKey: key };
  }
  return null;
}

function setMarketScanResult(ctxSeed, payload) {
  const keys = _makeAllBudgetKeys(ctxSeed);
  const ts = Date.now();
  // Pin the original query on the entry so a later cross-route hit can
  // detect when an enriched/refined follow-up query lands on the same
  // pool and log ENRICHED_QUERY_MARKET_CALL_BLOCKED.
  const originalQuery = (payload?.payload?.finalQuery)
    || (payload?.payload?.query)
    || ctxSeed?.query
    || null;
  for (const key of keys) {
    MARKET_SCAN_RESULT_CACHE.set(key, { ...payload, ts, key, originalQuery });
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// End Phase 2C.8 budget block
// ═══════════════════════════════════════════════════════════════════════════════

function shouldRunQueueWorkers() {
  return QUEUE_ENABLED && QUEUE_WORKERS_ENABLED && SERVER_ROLE !== "api";
}

function shouldRunSchedulers() {
  return SCHEDULERS_ENABLED && SERVER_ROLE !== "api" && leaderElection.isLeader();
}

async function cacheGet(key) {
  if (!redis) return null;

  try {
    const v = await redis.get(key);
    incrementMetric("redis_cache_get_total", {
      hit: v ? "1" : "0",
    });
    return v ? JSON.parse(v) : null;
  } catch (err) {
    incrementMetric("redis_cache_error_total", { op: "get" });

    Promise.resolve()
      .then(() =>
        emitOpsAlert(
          "redis_cache_error",
          {
            op: "get",
            key: safeStr(key, 140),
            reason: err?.message || String(err),
          },
          { severity: "error", skipRedis: true }
        )
      )
      .catch(() => {});

    return null;
  }
}

async function cacheSet(key, value, ttlSec = 3600) {
  if (!redis) return;

  try {
    await redis.setex(key, ttlSec, JSON.stringify(value));
    incrementMetric("redis_cache_set_total", {});
  } catch (err) {
    incrementMetric("redis_cache_error_total", { op: "set" });

    Promise.resolve()
      .then(() =>
        emitOpsAlert(
          "redis_cache_error",
          {
            op: "set",
            key: safeStr(key, 140),
            reason: err?.message || String(err),
          },
          { severity: "error", skipRedis: true }
        )
      )
      .catch(() => {});
  }
}

async function cacheDel(key) {
  if (!redis) return;

  try {
    await redis.del(key);
    incrementMetric("redis_cache_del_total", {});
  } catch (err) {
    incrementMetric("redis_cache_error_total", { op: "del" });

    Promise.resolve()
      .then(() =>
        emitOpsAlert(
          "redis_cache_error",
          {
            op: "del",
            key: safeStr(key, 140),
            reason: err?.message || String(err),
          },
          { severity: "error", skipRedis: true }
        )
      )
      .catch(() => {});
  }
}

const createDurableIdemMiddleware = createDurableIdempotencyMiddleware({
  redis,
  namespace: "evanai:idem:v2",
  defaultTtlSec: IDEMPOTENCY_TTL_SEC,
});

const createDurableUploadIdemMiddleware = createDurableIdempotencyMiddleware({
  redis,
  namespace: "evanai:idem:upload:v2",
  headerName: "x-upload-idempotency-key",
  defaultTtlSec: IDEMPOTENCY_TTL_SEC,
});

function retrievalSnapshotCacheKey(query = "") {
  return `retrieval:snapshot:${canonicalMarketQuery(query)}`;
}

function retrievalSearchCacheKey(query = "", limit = 24) {
  return `retrieval:search:${canonicalMarketQuery(query)}:${Number(limit || 24)}`;
}

async function invalidateRetrievalCaches(query = "") {
  const base = canonicalMarketQuery(query);
  if (!base) return;

  await cacheDel(retrievalSnapshotCacheKey(base));
  await cacheDel(retrievalSearchCacheKey(base, 12));
  await cacheDel(retrievalSearchCacheKey(base, 24));
  await cacheDel(retrievalSearchCacheKey(base, 40));
  await cacheDel(retrievalSearchCacheKey(base, 60));
}

async function getRetrievalSnapshotCached(query = "") {
  const key = retrievalSnapshotCacheKey(query);
  const cached = await cacheGet(key);
  if (cached?.items?.length) return cached;

  const live = await getQuerySnapshot(query);
  if (live?.items?.length) {
    await cacheSet(key, live, 300);
  }

  return live;
}

async function searchRetrievalIndexCached(query = "", limit = 24) {
  const key = retrievalSearchCacheKey(query, limit);
  const cached = await cacheGet(key);
  if (Array.isArray(cached)) return cached;

  const live = await searchRetrievalIndex(query, limit);
  if (Array.isArray(live) && live.length) {
    await cacheSet(key, live, 180);
  }

  return live;
}

const L2_STATE_REFRESH = new Map();

function shortHash(value = "") {
  return crypto.createHash("sha256").update(String(value)).digest("hex").slice(0, 32);
}

function stableStateKeyPart(value = "", max = 180) {
  return encodeURIComponent(String(value || "").trim().slice(0, max));
}

function mirrorStateWrite(cacheKey, value, ttlSec = STATE_MIRROR_TTL_SEC) {
  if (!redis) return;
  cacheSet(cacheKey, value, ttlSec).catch(() => {});
}

function scheduleRedisStateRefresh(cacheKey, apply, intervalMs = REDIS_STATE_REFRESH_MS) {
  if (!redis || !cacheKey || typeof apply !== "function") return;

  const now = Date.now();
  const meta = L2_STATE_REFRESH.get(cacheKey) || { at: 0, inflight: false };

  if (meta.inflight) return;
  if (now - meta.at < intervalMs) return;

  L2_STATE_REFRESH.set(cacheKey, { at: now, inflight: true });

  Promise.resolve()
    .then(() => cacheGet(cacheKey))
    .then((remote) => {
      if (remote != null) apply(remote);
    })
    .catch((err) => {
      logEvent("warn", "redis_state_refresh_failed", {
        cacheKey,
        error: err?.message || String(err),
      });
    })
    .finally(() => {
      L2_STATE_REFRESH.set(cacheKey, {
        at: Date.now(),
        inflight: false,
      });
    });
}

function distributedListTrim(list = [], maxAgeMs = 24 * 60 * 60 * 1000, maxItems = 512) {
  const now = Date.now();
  return (Array.isArray(list) ? list : [])
    .map((x) => Number(x || 0))
    .filter((x) => Number.isFinite(x) && now - x < maxAgeMs)
    .slice(-maxItems);
}

function sourceHealthCacheKey(source = "") {
  return `state:source_health:${stableStateKeyPart(String(source || "").toLowerCase())}`;
}

function sourceMemoryCacheKey(query = "") {
  return `state:source_memory:${stableStateKeyPart(normalizeQuery(query))}`;
}

function queryPulseCacheKey(query = "") {
  return `state:query_pulse:${stableStateKeyPart(canonicalMarketQuery(query))}`;
}

function inflightResultCacheKey(key = "") {
  return `state:inflight_result:${shortHash(key)}`;
}

function distributedLockCacheKey(key = "") {
  return `state:lock:${shortHash(key)}`;
}

const LOCAL_UPLOAD_TICKET_STORE = new Map();

setInterval(() => {
  const now = Date.now();
  for (const [id, ticket] of LOCAL_UPLOAD_TICKET_STORE.entries()) {
    if (Number(ticket?.expiresAt || 0) <= now) {
      LOCAL_UPLOAD_TICKET_STORE.delete(id);
    }
  }
}, 60 * 1000).unref?.();

function uploadTicketCacheKey(id) {
  return `upload_ticket:${safeStr(id, 120)}`;
}

async function saveUploadTicket(ticket) {
  if (!ticket?.id) return;

  if (redis) {
    await cacheSet(uploadTicketCacheKey(ticket.id), ticket, DIRECT_UPLOAD_TTL_SEC);
    return;
  }

  LOCAL_UPLOAD_TICKET_STORE.set(ticket.id, ticket);
}

async function readUploadTicket(id) {
  if (!id) return null;

  if (redis) {
    return await cacheGet(uploadTicketCacheKey(id));
  }

  const ticket = LOCAL_UPLOAD_TICKET_STORE.get(id);
  if (!ticket) return null;
  if (Number(ticket.expiresAt || 0) <= Date.now()) {
    LOCAL_UPLOAD_TICKET_STORE.delete(id);
    return null;
  }
  return ticket;
}

async function deleteUploadTicket(id) {
  if (!id) return;

  if (redis) {
    await cacheDel(uploadTicketCacheKey(id));
    return;
  }

  LOCAL_UPLOAD_TICKET_STORE.delete(id);
}

async function createDirectUploadSession({
  userId,
  contentType,
  sizeBytes,
  filename = "",
} = {}) {
  const ext = extensionFromMime(contentType || guessMimeFromKey(filename) || "");
  const objectKey =
    `uploads/raw/${safeStr(userId || "anon", 64)}/` +
    `${Date.now()}_${crypto.randomBytes(8).toString("hex")}.${ext}`;

  if (canUseS3ObjectStore()) {
    const [client, { PutObjectCommand, getSignedUrl }] = await Promise.all([getS3Client(), getS3SDK()]);
    const command = new PutObjectCommand({
      Bucket: OBJECT_STORE_BUCKET,
      Key: objectKey,
      ContentType: contentType || "application/octet-stream",
      Metadata: normalizeObjectMetadata({
        userId: userId || "anon",
        uploadType: "scan_raw",
      }),
    });

    const uploadUrl = await getSignedUrl(client, command, {
      expiresIn: PRESIGNED_UPLOAD_TTL_SEC,
    });

    return {
      provider: "s3",
      objectKey,
      uploadUrl,
      method: "PUT",
      headers: {
        "Content-Type": contentType || "application/octet-stream",
      },
      expiresInSec: PRESIGNED_UPLOAD_TTL_SEC,
      maxBytes: sizeBytes || MAX_UPLOAD_BYTES,
    };
  }

  const ticket = {
    id: `upl_${Date.now()}_${crypto.randomBytes(8).toString("hex")}`,
    objectKey,
    userId: userId || null,
    contentType: contentType || "application/octet-stream",
    maxBytes: sizeBytes || MAX_UPLOAD_BYTES,
    createdAt: Date.now(),
    expiresAt: Date.now() + DIRECT_UPLOAD_TTL_SEC * 1000,
  };

  await saveUploadTicket(ticket);

  return {
    provider: "local",
    objectKey,
    uploadUrl: `/upload/direct/${ticket.id}`,
    method: "PUT",
    headers: {
      "Content-Type": ticket.contentType,
    },
    expiresInSec: DIRECT_UPLOAD_TTL_SEC,
    maxBytes: ticket.maxBytes,
    ticketId: ticket.id,
  };
}

// -------------------- REFERRAL ENGINE --------------------

const REFERRAL_BONUS_REWARD = 3;

function generateReferralCode() {
  return crypto.randomBytes(4).toString("hex").toUpperCase();
}

function referralCodeKey(code) {
  return `referral:${safeStr(code, 32).toUpperCase()}`;
}

function referralOwnerKey(ownerId) {
  return `referral_owner:${safeStr(ownerId, 64)}`;
}

function referralUserKey(userId) {
  return `referral_user:${safeStr(userId, 64)}`;
}

// Tracks per-device redemptions so the same device can't redeem twice
// even if the user creates a new account.
function referralInstallKey(installId) {
  return `referral_install:${safeStr(installId, 128)}`;
}

// Pending: a referral link was clicked on this device but not yet redeemed.
// Stored until the user authenticates and calls /referral/redeem.
function referralPendingKey(installId) {
  return `referral_pending:${safeStr(installId, 128)}`;
}

async function createReferral(ownerId) {
  if (!redis) return null;

  const cleanOwnerId = safeStr(ownerId, 64);
  if (!cleanOwnerId) return null;

  const existingCode = await redis.get(referralOwnerKey(cleanOwnerId));
  if (existingCode) {
    const existingRecord = await redis.get(referralCodeKey(existingCode));
    if (existingRecord) return existingCode;
  }

  for (let i = 0; i < 8; i++) {
    const code = generateReferralCode();
    const codeKey = referralCodeKey(code);
    const exists = await redis.get(codeKey);
    if (exists) continue;

    const payload = {
      ownerId: cleanOwnerId,
      code,
      uses: 0,
      createdAt: Date.now(),
    };

    await redis
      .multi()
      .set(codeKey, JSON.stringify(payload))
      .set(referralOwnerKey(cleanOwnerId), code)
      .exec();

    return code;
  }

  return null;
}

async function getReferralByOwner(ownerId) {
  if (!redis) return null;

  const cleanOwnerId = safeStr(ownerId, 64);
  if (!cleanOwnerId) return null;

  const code = await redis.get(referralOwnerKey(cleanOwnerId));
  if (!code) return null;

  const raw = await redis.get(referralCodeKey(code));
  if (!raw) return null;

  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

async function redeemReferral({ code, userId, installId, source = "manual" }) {
  if (!redis) return { ok: false, reason: "redis_unavailable" };

  const cleanCode    = safeStr(code, 32).toUpperCase();
  const cleanUserId  = safeStr(userId || "", 64);
  const cleanInstall = safeStr(installId || "", 128);
  const cleanSource  = safeStr(source || "manual", 24) || "manual";

  // Both userId and installId required — confirms the user actually has the app installed.
  if (!cleanCode || !cleanUserId) {
    return { ok: false, reason: "sign_in_required" };
  }

  // Look up the code
  const raw = await redis.get(referralCodeKey(cleanCode));
  if (!raw) return { ok: false, reason: "invalid_code" };

  let referral = null;
  try {
    referral = JSON.parse(raw);
  } catch {
    return { ok: false, reason: "invalid_code" };
  }

  if (!referral?.ownerId) {
    return { ok: false, reason: "invalid_code" };
  }

  // Cannot use your own code
  if (String(referral.ownerId) === String(cleanUserId)) {
    return { ok: false, reason: "self_referral_not_allowed" };
  }

  // Cannot redeem if this account already has (userId-level lock)
  const existingUserRedeem = await redis.get(referralUserKey(cleanUserId));
  if (existingUserRedeem) {
    return { ok: false, reason: "already_redeemed" };
  }

  // Cannot redeem if this physical device already has (installId-level lock)
  // This prevents uninstall + reinstall + new account farming.
  if (cleanInstall) {
    const existingInstallRedeem = await redis.get(referralInstallKey(cleanInstall));
    if (existingInstallRedeem) {
      return { ok: false, reason: "already_redeemed_device" };
    }
  }

  referral.uses = Number(referral.uses || 0) + 1;

  const redeemPayload = {
    code: cleanCode,
    ownerId: referral.ownerId,
    redeemedAt: Date.now(),
    source: cleanSource,
    installId: cleanInstall || null,
  };

  const multi = redis
    .multi()
    .set(referralCodeKey(cleanCode), JSON.stringify(referral))
    .set(referralUserKey(cleanUserId), JSON.stringify(redeemPayload));

  // Bind the device too
  if (cleanInstall) {
    multi.set(referralInstallKey(cleanInstall), JSON.stringify(redeemPayload));
    // Clean up pending record now that it's been redeemed
    multi.del(referralPendingKey(cleanInstall));
  }

  await multi.exec();

  return {
    ok: true,
    ownerId: referral.ownerId,
    code: cleanCode,
    uses: referral.uses,
    source: cleanSource,
  };
}

// Register that a referral link was clicked on this device (pre-auth).
// Does NOT grant rewards. Just persists the intent so it survives until
// the user authenticates and calls /referral/redeem.
async function registerPendingReferral(installId, code) {
  if (!redis || !installId || !code) return false;
  const cleanInstall = safeStr(installId, 128);
  const cleanCode    = safeStr(code, 32).toUpperCase();
  if (!cleanInstall || !cleanCode) return false;

  // Verify the code actually exists before persisting
  const raw = await redis.get(referralCodeKey(cleanCode));
  if (!raw) return false;

  // Don't overwrite an already-redeemed install
  const already = await redis.get(referralInstallKey(cleanInstall));
  if (already) return false;

  // Store with 30-day TTL (enough time for the user to finish signup)
  await redis.set(
    referralPendingKey(cleanInstall),
    JSON.stringify({ code: cleanCode, registeredAt: Date.now() }),
    "EX",
    60 * 60 * 24 * 30,
  );
  return true;
}

// -------------------- TTL cache (prevents memory leak) --------------------
class TTLCache {
  constructor({ ttlMs, maxSize }) {
    this.ttlMs = ttlMs;
    this.maxSize = maxSize;
    this.map = new Map(); // key -> { v, exp }
  }
  get(key) {
    const hit = this.map.get(key);
    if (!hit) return null;
    if (hit.exp < Date.now()) {
      this.map.delete(key);
      return null;
    }
    return hit.v;
  }
  set(key, value) {
    // basic prune if oversized
    if (this.map.size >= this.maxSize) this.prune(0.15);
    this.map.set(key, { v: value, exp: Date.now() + this.ttlMs });
    return value;
  }
  prune(fraction = 0.2) {
    const target = Math.floor(this.maxSize * (1 - fraction));
    if (this.map.size <= target) return;

    // remove expired first
    const now = Date.now();
    for (const [k, entry] of this.map) {
      if (entry.exp < now) this.map.delete(k);
    }
    if (this.map.size <= target) return;

    // then remove oldest insertion order
    while (this.map.size > target) {
      const firstKey = this.map.keys().next().value;
      this.map.delete(firstKey);
    }
  }
  size() {
    return this.map.size;
  }
}

// -------------------- In-flight dedupe (prevents stampede) --------------------
const inflight = new Map();

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function acquireDistributedLock(rawKey, ttlMs = DISTRIBUTED_LOCK_TTL_MS) {
  if (!redis) return null;

  const lockKey = distributedLockCacheKey(rawKey);
  const token = `${INSTANCE_ID}:${Date.now()}:${crypto.randomBytes(6).toString("hex")}`;

  try {
    const ok = await redis.set(lockKey, token, "PX", ttlMs, "NX");
    if (ok !== "OK") return null;

    return {
      lockKey,
      token,
    };
  } catch {
    return null;
  }
}

async function releaseDistributedLock(lock) {
  if (!redis || !lock?.lockKey || !lock?.token) return;

  try {
    await redis.eval(
      `
      if redis.call("GET", KEYS[1]) == ARGV[1] then
        return redis.call("DEL", KEYS[1])
      end
      return 0
      `,
      1,
      lock.lockKey,
      lock.token
    );
  } catch {}
}

async function publishInflightResult(rawKey, payload, ok = true, error = null) {
  if (!redis) return;

  await cacheSet(
    inflightResultCacheKey(rawKey),
    {
      ok,
      payload: ok ? payload : null,
      error: ok ? null : String(error || "inflight_failed"),
      instanceId: INSTANCE_ID,
      ts: Date.now(),
    },
    Math.max(15, Math.ceil(DISTRIBUTED_WAIT_MS / 1000) + 5)
  );
}

async function waitForInflightResult(rawKey, maxWaitMs = DISTRIBUTED_WAIT_MS) {
  if (!redis) return { hit: false, payload: null };

  const startedAt = Date.now();

  while (Date.now() - startedAt < maxWaitMs) {
    const shared = await cacheGet(inflightResultCacheKey(rawKey));

    if (shared?.ok === true) {
      return { hit: true, payload: shared.payload };
    }

    if (shared?.ok === false) {
      return { hit: false, payload: null };
    }

    await sleep(DISTRIBUTED_POLL_MS);
  }

  return { hit: false, payload: null };
}

async function withInflight(key, fn) {
  if (inflight.has(key)) return inflight.get(key);

  const p = (async () => {
    let lock = null;

    try {
      if (redis) {
        lock = await acquireDistributedLock(`inflight:${key}`);

        if (!lock) {
          const shared = await waitForInflightResult(`inflight:${key}`);
          if (shared.hit) {
            incMetric("distributed_inflight_hit_total", 1, {});
            return shared.payload;
          }
        }
      }

      const result = await fn();

      if (redis) {
        await publishInflightResult(`inflight:${key}`, result, true, null);
      }

      return result;
    } catch (err) {
      if (redis) {
        await publishInflightResult(
          `inflight:${key}`,
          null,
          false,
          err?.message || String(err)
        );
      }
      throw err;
    } finally {
      inflight.delete(key);
      if (lock) {
        await releaseDistributedLock(lock);
      }
    }
  })();

  inflight.set(key, p);
  return p;
}

// -------------------- Caches --------------------
// Bump CACHE_SCHEMA_VERSION whenever the shape of cached items/payloads
// changes incompatibly. All in-memory + persisted caches use this as a
// prefix on their keys, so old entries become orphans (and naturally
// expire) instead of returning broken data. v3 = post-cluster-spread fix
// (items with proper top-level title/price/source instead of {0: listing}).
const CACHE_SCHEMA_VERSION = String(process.env.CACHE_SCHEMA_VERSION || "v3");

// Vision results: long-ish TTL; limited size
const visionCache = new TTLCache({ ttlMs: 24 * 60 * 60 * 1000, maxSize: 1200 });
// SERP caches: short TTL
const SERP_CACHE = new TTLCache({ ttlMs: 5 * 60 * 1000, maxSize: 1200 });

// ── L2 Redis persistence for SERP_CACHE ───────────────────────────────────
// In-memory L1 is wiped on every server restart, which means the first
// /watch/poll after restart pays full SerpAPI cost for every saved item
// (5 lanes × 3 items = 15 SerpAPI calls per cold-launch app open in the
// observed live trace). Mirroring writes to Redis lets a restarted process
// hydrate L1 from L2 on first read, so a restart inside the 5-min TTL
// window pays nothing instead of paying full cost.
const SERP_CACHE_REDIS_PREFIX  = `serpcache:${CACHE_SCHEMA_VERSION}:`;
const SERP_CACHE_REDIS_TTL_SEC = 5 * 60;

async function serpCacheGetWithRedis(key) {
  const mem = SERP_CACHE.get(key);
  if (mem) return mem;
  if (!redis) return null;
  try {
    const raw = await redis.get(`${SERP_CACHE_REDIS_PREFIX}${key}`);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed) && parsed.length) {
      SERP_CACHE.set(key, parsed); // hydrate L1 (also re-writes to Redis, idempotent)
      return parsed;
    }
  } catch {}
  return null;
}

// Wrap SERP_CACHE.set so every legacy call site automatically writes to
// Redis L2 without touching their existing sync API. Redis write is
// fire-and-forget via setImmediate — caller is not delayed.
const _origSerpCacheSet = SERP_CACHE.set.bind(SERP_CACHE);
SERP_CACHE.set = function _serpCacheSetWithRedisMirror(key, value) {
  const v = _origSerpCacheSet(key, value);
  if (redis && Array.isArray(value) && value.length) {
    setImmediate(() => {
      redis
        .set(
          `${SERP_CACHE_REDIS_PREFIX}${key}`,
          JSON.stringify(value),
          "EX",
          SERP_CACHE_REDIS_TTL_SEC
        )
        .catch(() => {});
    });
  }
  return v;
};

// SerpAPI hardened cache (Phase 6, SWR): fresh hit → instant, stale hit →
// returned instantly + background refresh, miss → live fetch with timeout.
// TTLs are env-driven (SERPAPI_CACHE_TTL_MS / SERPAPI_STALE_TTL_MS, defaults
// 6h / 24h) so a viral scan day can extend the stale window without a deploy.
const SERP_HARDENED_CACHE = new SerpCache({
  freshTtlMs: SERPAPI_CACHE_TTL_MS,
  staleTtlMs: SERPAPI_STALE_TTL_MS,
  maxSize:    2500,
});
const RESEARCH_CACHE = new TTLCache({ ttlMs: 5 * 60 * 1000, maxSize: 1000 });
const LOCAL_CACHE = new TTLCache({ ttlMs: 10 * 60 * 1000, maxSize: 600 });

// ── WS7: Calibration suppression cache (in-memory, 5-min TTL) ─────────────
// Warmed at startup and after each weekly audit. Allows assembleProfitIntel
// (synchronous) to check category-level suppression without an async Redis call.
const _suppressionCache = new Map(); // "cat:signal" → { capped: bool, loadedAt: number }
const SUPPRESSION_CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes

async function warmSuppressionCache() {
  if (!redis) return;
  try {
    const suppressions = await getAllSuppressions(redis);
    // Clear entries that no longer exist
    for (const [k] of _suppressionCache) {
      const [cat, ...sigParts] = k.split(":");
      const sig = sigParts.join(":");
      if (!suppressions.some(s => normalizeSuppressKey(s.category) === cat && s.signalType === sig)) {
        _suppressionCache.delete(k);
      }
    }
    for (const { category, signalType } of suppressions) {
      _suppressionCache.set(`${normalizeSuppressKey(category)}:${signalType}`, { capped: true, loadedAt: Date.now() });
    }
  } catch { /* non-fatal */ }
}

function getSuppressionCached(category, signal) {
  if (!category || !signal) return false;
  const k = `${normalizeSuppressKey(category)}:${signal}`;
  const entry = _suppressionCache.get(k);
  if (!entry) return false;
  if (Date.now() - entry.loadedAt > SUPPRESSION_CACHE_TTL_MS) {
    _suppressionCache.delete(k);
    return false;
  }
  return entry.capped;
}

function normalizeSuppressKey(cat) {
  return String(cat || "general").toLowerCase().replace(/[^a-z0-9_]/g, "_").slice(0, 40);
}

// ── Reseller Rivalry tracker (in-memory, rolling 2hr window) ───────────
const RIVALRY_MAP = new Map(); // key: normalizedQuery → [{ userId, ts }]
const RIVALRY_TTL_MS = 2 * 60 * 60 * 1000; // 2 hours

const EBAY_RENDER_CACHE = new TTLCache({
  ttlMs: 10 * 60 * 1000,
  maxSize: 300,
});

const EBAY_RENDER_SKIP_CACHE = new TTLCache({
  ttlMs: 2 * 60 * 1000,
  maxSize: 400,
});


const QUERY_LEARNING = new Map();
const INSTANT_SCAN_CACHE = new TTLCache({
  ttlMs: 2 * 60 * 60 * 1000,
  maxSize: 2500,
});
const QUERY_PULSE = new Map();

// ── Result-Aware Feedback Loop state ─────────────────────────────────────────
const RESULT_CONSENSUS_CACHE = new TTLCache({ ttlMs: 10 * 60 * 1000, maxSize: 400 });
const QUERY_SUCCESS_MEMORY   = new Map(); // normalizedQuery → { count, category, lastSeen }
const QUERY_MEMORY_MAX       = 500;
// ── Scan stream pipeline metrics (in-memory rolling counters) ─────────────────
const _scanStreamMetrics = {
  totalRequests:       0,
  totalCompleted:      0,
  totalPhase1:         0,
  cacheHits:           0,
  oracleInvocations:   0,
  oracleTimeouts:      0,
  oracleSkips:         0,  // oracle eligible but skipped by shouldInvokeOracle
  provisionalSent:     0,
  earlyProvisionalSent: 0, // provisional from fast native lanes before SerpAPI
  degradedCompletions: 0,
  inflightHits:        0,
  phase1TotalMs:       [], // rolling last 200
  phase2TotalMs:       [], // rolling last 200
  ttfrMs:              [], // time-to-first-result (provisional or complete), rolling 200
  oracleSkipReasons:   {}, // reason string → count
  oracleInvokeReasons: {}, // reason string → count
  sourceItemTotals:    {}, // srcGroup → total items contributed across all scans (LiveAggregator)
};
function _recordStreamMetric(key, value) {
  if (!(key in _scanStreamMetrics)) return;
  const v = _scanStreamMetrics[key];
  if (typeof v === "number") { _scanStreamMetrics[key]++; }
  else if (Array.isArray(v)) {
    v.push(value);
    if (v.length > 200) v.shift();
  } else if (v !== null && typeof v === "object") {
    // reason map: value is the reason string
    const r = String(value || "unknown");
    _scanStreamMetrics[key][r] = (_scanStreamMetrics[key][r] || 0) + 1;
  }
}
// ── Scan stream Phase 3 — enrichment cache + pipeline constants ───────────────
const ENRICHED_SCAN_CACHE        = new TTLCache({ ttlMs: 5 * 60 * 1000, maxSize: 800 });
const STREAM_PHASE1_INFLIGHT     = new Map(); // cacheKey → Promise<items[]>
const SCAN_STREAM_ORACLE_THRESHOLD = 3;       // invoke oracle when fewer than this many marketplace items
// Phase 4H.5: default is now 1700ms (5000ms SLA - 3300ms vision = 1700ms for market).
// Dynamic deadline is computed per-request from scanStartedAtMs when provided by client.
const MARKET_FIRST_PAYLOAD_DEADLINE_MS = Number(process.env.MARKET_FIRST_PAYLOAD_DEADLINE_MS || 1700);
// Background recovery calls have no real-time SLA pressure — give market 6s to find results.
const MARKET_BACKGROUND_RECOVERY_DEADLINE_MS = Number(process.env.MARKET_BACKGROUND_RECOVERY_DEADLINE_MS || 6000);
// High-confidence exact identity (query_fast ≥ 0.85): raise market floor to 3s so
// SerpAPI has enough time even when vision used most of the 5s SLA window.
const MARKET_EXACT_IDENTITY_MIN_MS = Number(process.env.MARKET_EXACT_IDENTITY_MIN_MS || 3000);
// In-memory store for background master identity results (imageHash/scanId → result).
const BACKGROUND_VISION_RESULTS = new Map(); // key → {query,variants,confidence,visionIdentity,category,completedAt,elapsedMs}
// Oracle is the GPT-fabricated synthetic-comp fallback used when phase1 is thin.
// Was 8s — that's the entire user-perceived latency on degraded scans where
// every external auth is dead. The buyOrPass engine now produces an honest
// HOLD@15 verdict on no data, so the marginal value of a 3+s oracle wait is low:
// the user already has a verdict; oracle just adds optional enrichment.
// 3s is enough for typical gpt-4 oracle calls (~1.5–2.5s) while letting the
// `complete` event fire fast on auth-broken scans.
const SCAN_STREAM_ORACLE_BUDGET_MS = Number(process.env.SCAN_STREAM_ORACLE_BUDGET_MS || 3000);
// Critical-mode budget: used when phase1 returned zero items (SerpAPI down,
// no marketplace APIs configured). Oracle is the entire comp pool, so we give
// it enough time to actually return — otherwise every scan in degraded mode
// silently fails with "no_results". Matches the legacy /market/search path
// which doesn't cap Oracle.
const SCAN_STREAM_ORACLE_BUDGET_CRITICAL_MS = Number(process.env.SCAN_STREAM_ORACLE_BUDGET_CRITICAL_MS || 7000);

function scanLog(event, scanId, fields = {}) {
  try { console.log(JSON.stringify({ event, scanId, ts: Date.now(), ...fields })); } catch {}
}

// ── Phase 4: Source policy classification ────────────────────────────────────
// Each source is classified by tier, trust, latency tolerance, and whether it
// contributes to provisional results or is enrichment/oracle-only.
const SOURCE_POLICY = {
  ebay:     { tier: "primary",     trustMult: 1.00, provisionalEligible: true,  droppable: false, latencyBudgetMs: 4000 },
  walmart:  { tier: "primary",     trustMult: 0.90, provisionalEligible: true,  droppable: false, latencyBudgetMs: 4000 },
  bestbuy:  { tier: "primary",     trustMult: 0.88, provisionalEligible: true,  droppable: false, latencyBudgetMs: 4000 },
  etsy:     { tier: "primary",     trustMult: 0.80, provisionalEligible: false, droppable: true,  latencyBudgetMs: 5000 },
  amazon:   { tier: "secondary",   trustMult: 0.88, provisionalEligible: false, droppable: true,  latencyBudgetMs: 8000 },
  serpapi:  { tier: "secondary",   trustMult: 0.75, provisionalEligible: false, droppable: true,  latencyBudgetMs: 8000 },
  stockx:   { tier: "enrichment",  trustMult: 0.82, provisionalEligible: false, droppable: true,  latencyBudgetMs: 8000 },
  poshmark: { tier: "enrichment",  trustMult: 0.70, provisionalEligible: false, droppable: true,  latencyBudgetMs: 8000 },
  mercari:  { tier: "enrichment",  trustMult: 0.68, provisionalEligible: false, droppable: true,  latencyBudgetMs: 8000 },
  depop:    { tier: "enrichment",  trustMult: 0.65, provisionalEligible: false, droppable: true,  latencyBudgetMs: 8000 },
  grailed:  { tier: "enrichment",  trustMult: 0.67, provisionalEligible: false, droppable: true,  latencyBudgetMs: 8000 },
  bing:     { tier: "fallback",    trustMult: 0.50, provisionalEligible: false, droppable: true,  latencyBudgetMs: 6000 },
  googlecse:{ tier: "fallback",    trustMult: 0.50, provisionalEligible: false, droppable: true,  latencyBudgetMs: 6000 },
  oracle:   { tier: "oracle",      trustMult: 0.62, provisionalEligible: false, droppable: true,  latencyBudgetMs: 8000 },
};

// Normalize a raw source/store string to one of the SOURCE_POLICY keys.
function sourceGroup(item) {
  const s = String(item?.source || item?.store || item?.vendor || item?.merchant_name || "").toLowerCase();
  if (s.includes("ebay"))                    return "ebay";
  if (s.includes("walmart"))                 return "walmart";
  if (/best.?buy/i.test(s))                  return "bestbuy";
  if (s.includes("amazon"))                  return "amazon";
  if (s.includes("etsy"))                    return "etsy";
  if (s.includes("stockx"))                  return "stockx";
  if (s.includes("poshmark"))                return "poshmark";
  if (s.includes("mercari"))                 return "mercari";
  if (s.includes("depop"))                   return "depop";
  if (s.includes("grailed"))                 return "grailed";
  if (s.includes("bing") || s.includes("microsoft")) return "bing";
  if (s.includes("google"))                  return "googlecse";
  return "other";
}

// Canonical item key: identifies the same physical listing across sources.
// Uses $2 price bucket to tolerate minor price fluctuations.
function canonicalItemKey(item) {
  const title     = normalizeTitleKey(item?.title || "");
  const price     = Number(item?.totalPrice ?? item?.price ?? 0);
  const pBucket   = Number.isFinite(price) ? Math.round(price / 2) : 0;
  const srcGroup  = sourceGroup(item);
  // Include source so same item on eBay vs Walmart gets distinct IDs (intentional)
  return `${title}|${pBucket}|${srcGroup}`;
}

// Assign deterministic _itemId and _srcGroup to every item.
// Items retain their _itemId when they reappear in enriched/complete results,
// enabling stable React keys on the client.
function assignItemIds(items) {
  if (!Array.isArray(items)) return [];
  const keyCounts = {};
  return items.map((item) => {
    if (item?._itemId) return item;          // already assigned — preserve it
    const base  = canonicalItemKey(item);
    const count = (keyCounts[base] = (keyCounts[base] || 0) + 1);
    return {
      ...item,
      _itemId:   count === 1 ? base : `${base}#${count}`,
      _srcGroup: item._srcGroup || sourceGroup(item),
    };
  });
}

// Smart oracle decision function — replaces the blunt item-count threshold.
// Returns { invoke: bool, reason: string, factors: object }.
//
// Oracle is skipped when:
//   • Item count is sufficient (≥6)
//   • 3+ items from primary trusted sources with tight price spread
//   • Identity too weak for oracle to help (oracle can't fix bad vision match)
//   • Chaotic spread + weak identity → oracle won't clarify a bad match
//   • Adequate diverse evidence already exists
//
// Oracle is invoked when:
//   • No market data at all
//   • Only scrape/weak sources, no native API results
//   • Low count AND no trusted primary source
//
function shouldInvokeOracle(items, context = {}) {
  const { visionIdentity = null, category = null } = context;

  const count   = Array.isArray(items) ? items.length : 0;
  const factors = {};

  // Hard skip: abundant data
  if (count >= 6) {
    return { invoke: false, reason: "sufficient_items", factors: { count } };
  }

  // Assess identity quality from vision metadata
  const identityConf = Number(
    visionIdentity?.confidence ?? visionIdentity?.visionConfidence ?? 0.5
  );
  factors.identityConf = Math.round(identityConf * 100) / 100;

  // Hard skip: identity too weak — oracle generates synthetic listings for an
  // unknown item, adding noise, not depth. Trust gates will suppress anyway.
  if (identityConf < 0.18) {
    return { invoke: false, reason: "identity_too_weak", factors };
  }

  // Source diversity analysis
  const srcGroups = new Set(
    items.map(i => sourceGroup(i)).filter(s => s !== "other" && s !== "oracle")
  );
  const hasPrimaryTrusted = items.some(i =>
    ["ebay", "walmart", "bestbuy", "amazon"].includes(sourceGroup(i))
  );

  // Price spread analysis
  const prices = items
    .map(i => Number(i?.totalPrice ?? i?.price))
    .filter(n => Number.isFinite(n) && n > 0);
  const medianPrice = prices.length
    ? prices.slice().sort((a, b) => a - b)[Math.floor(prices.length / 2)]
    : 0;
  const spread = prices.length >= 2 && medianPrice > 0
    ? (Math.max(...prices) - Math.min(...prices)) / medianPrice
    : 0;

  factors.count            = count;
  factors.srcGroups        = srcGroups.size;
  factors.hasPrimaryTrusted = hasPrimaryTrusted;
  factors.priceSpread      = Math.round(spread * 100) / 100;

  // Strong evidence: 3+ items, at least one trusted primary, tight spread, diverse sources
  if (count >= 3 && hasPrimaryTrusted && spread < 0.9 && srcGroups.size >= 2) {
    return { invoke: false, reason: "strong_primary_evidence", factors };
  }

  // No data at all → oracle definitely needed
  if (count === 0) {
    return { invoke: true, reason: "no_market_data", factors };
  }

  // Only scrape/weak sources with count below threshold
  if (count < SCAN_STREAM_ORACLE_THRESHOLD && !hasPrimaryTrusted) {
    return { invoke: true, reason: "no_trusted_primary_source", factors };
  }

  // Chaotic spread + weak identity → oracle won't improve coherence, skip it
  if (spread > 2.0 && identityConf < 0.40) {
    return { invoke: false, reason: "chaotic_spread_weak_identity", factors };
  }

  // Adequate diverse evidence even if count is low
  if (count >= 2 && srcGroups.size >= 2 && hasPrimaryTrusted) {
    return { invoke: false, reason: "adequate_diverse_evidence", factors };
  }

  // Default: use count threshold
  const invoke = count < SCAN_STREAM_ORACLE_THRESHOLD;
  return {
    invoke,
    reason: invoke ? "low_count_default" : "sufficient_count_default",
    factors,
  };
}
// ── Phase 4: Conflict resolution for live aggregation ────────────────────────
// Called when the same canonical item key (or near-duplicate title+price bucket)
// appears from multiple sources. Returns the action to take:
//   "upgrade" — replace existing with incoming (incoming is higher-trust)
//   "ignore"  — keep existing (existing is same or higher trust)
// Note: "insert" (no conflict) is handled by LiveAggregator._resolve, not here.
function stableMerge(existing, incoming) {
  const existTrust  = SOURCE_POLICY[existing?._srcGroup]?.trustMult  ?? 0.50;
  const incomeTrust = SOURCE_POLICY[incoming?._srcGroup]?.trustMult  ?? 0.50;

  // Incoming is from a meaningfully higher-trust source → upgrade
  if (incomeTrust > existTrust + 0.05) return "upgrade";

  // Same trust tier: prefer the item with more non-null fields (data completeness)
  if (Math.abs(incomeTrust - existTrust) <= 0.05) {
    const existFields  = Object.values(existing  || {}).filter(v => v != null).length;
    const incomFields  = Object.values(incoming  || {}).filter(v => v != null).length;
    return incomFields > existFields + 2 ? "upgrade" : "ignore";
  }

  // Existing is from higher-trust source → keep it
  return "ignore";
}

// ── Phase 4: LiveAggregator — incremental source-arrival state machine ────────
// Manages a Map<_itemId, item> of the best known item for each canonical ID.
// Sources can ingest items at any time; the aggregator resolves conflicts via
// stableMerge and tracks per-source contribution statistics.
//
// Usage in stream route:
//   const agg = new LiveAggregator();
//   agg.ingest("phase1",  phase1Items);          // Tier A results (already ID-stamped)
//   agg.ingest("oracle",  oracleItems);           // Phase 2 oracle results
//   const enrichedItems = agg.snapshot();
//   scanLog("source_contributions", scanId, { sourceStats: agg.sourceStats() });
//
class LiveAggregator {
  constructor() {
    this._items        = new Map();  // _itemId → item (best known version)
    this._srcStats     = new Map();  // sourceName → { added, upgraded, ignored }
    this._t0           = Date.now();
    this._firstResultMs = null;
    this._ingestCount  = 0;
  }

  // Ingest items from a named source.
  // Items may or may not already have _itemId stamped — assignItemIds is called here.
  ingest(sourceName, rawItems) {
    if (!Array.isArray(rawItems) || !rawItems.length) return this;
    if (!this._srcStats.has(sourceName)) {
      this._srcStats.set(sourceName, { added: 0, upgraded: 0, ignored: 0 });
    }
    const stats   = this._srcStats.get(sourceName);
    const stamped = assignItemIds(rawItems);  // idempotent — preserves existing _itemId

    for (const item of stamped) {
      const action = this._resolve(item);
      if (action === "upgrade") {
        this._items.set(item._itemId, item);
        stats.upgraded++;
      } else if (action === "insert") {
        this._items.set(item._itemId, item);
        stats.added++;
        if (this._firstResultMs === null) this._firstResultMs = Date.now() - this._t0;
      } else {
        // "ignore"
        stats.ignored++;
      }
    }
    this._ingestCount++;
    return this;  // chainable
  }

  // Internal: classify an incoming item against current state.
  // Returns "upgrade" | "insert" | "ignore".
  _resolve(incoming) {
    // Exact _itemId match → conflict, delegate to stableMerge
    if (this._items.has(incoming._itemId)) {
      return stableMerge(this._items.get(incoming._itemId), incoming);
    }

    // Near-duplicate: same normalized title + same $2 price bucket (cross-source duplicate)
    // e.g. eBay direct API result vs. SerpAPI scrape of the same eBay listing
    const incomeTB = _titleBucket(incoming);
    if (incomeTB !== "|0") {  // skip zero-price items — too ambiguous
      for (const existing of this._items.values()) {
        if (_titleBucket(existing) === incomeTB) {
          return stableMerge(existing, incoming);
        }
      }
    }

    return "insert";
  }

  // Return all aggregated items as an ordered array (Map insertion order = first-seen).
  snapshot() {
    return Array.from(this._items.values());
  }

  // Return per-source contribution stats as a plain object.
  sourceStats() {
    const out = {};
    for (const [src, s] of this._srcStats.entries()) {
      out[src] = { added: s.added, upgraded: s.upgraded, ignored: s.ignored };
    }
    return out;
  }

  get size()          { return this._items.size; }
  get firstResultMs() { return this._firstResultMs; }
  get ingestCount()   { return this._ingestCount; }
}

// Helper: `titleNormalized|$2-priceBucket` for near-duplicate detection.
function _titleBucket(item) {
  const title  = normalizeTitleKey(item?.title || "");
  const price  = Number(item?.totalPrice ?? item?.price ?? 0);
  const bucket = Number.isFinite(price) ? Math.round(price / 2) : 0;
  return `${title}|${bucket}`;
}

// ─────────────────────────────────────────────────────────────────────────────

function rememberBetterQuery(original, improved) {
  const o = normalizeQuery(original);
  const i = normalizeQuery(improved);

  if (!o || !i || o === i) return;
  QUERY_LEARNING.set(o, i);
}

function scanFingerprint(query = "", variants = []) {
  const payload = {
    schemaVersion: CACHE_SCHEMA_VERSION,
    query: canonicalMarketQuery(query),
    variants: uniqueQueries(variants)
      .map((x) => canonicalMarketQuery(x))
      .filter(Boolean)
      .sort(),
  };

  return sha256(Buffer.from(JSON.stringify(payload))).slice(0, 24);
}

setInterval(() => {
  visionCache.prune();
  SERP_CACHE.prune();
  RESEARCH_CACHE.prune();
  LOCAL_CACHE.prune();
}, 60 * 1000);

const PHASE5_COUNTERS = new Map();
const PHASE5_LATENCIES = new Map();
const PHASE5_ALERTS_L1 = [];
const PHASE5_DRILLS_L1 = [];
const PHASE5_ALERT_DEDUPE = new Map();

const EDGE_COUNTER_L1 = new TTLCache({
  ttlMs: PHASE5_ABUSE_WINDOW_MS,
  maxSize: 12000,
});

function stableStringify(value) {
  const seen = new WeakSet();

  const sortValue = (input) => {
    if (input === null || typeof input !== "object") return input;
    if (seen.has(input)) return "[circular]";
    seen.add(input);

    if (Array.isArray(input)) {
      return input.map(sortValue);
    }

    return Object.keys(input)
      .sort()
      .reduce((acc, key) => {
        acc[key] = sortValue(input[key]);
        return acc;
      }, {});
  };

  try {
    return JSON.stringify(sortValue(value));
  } catch {
    return JSON.stringify({ value: "[unserializable]" });
  }
}

function metricKey(name, tags = {}) {
  const sortedTags = Object.keys(tags)
    .sort()
    .reduce((acc, key) => {
      acc[key] = tags[key];
      return acc;
    }, {});
  return `${name}|${stableStringify(sortedTags)}`;
}

function incrementMetric(name, tags = {}, value = 1) {
  const key = metricKey(name, tags);
  const prev = PHASE5_COUNTERS.get(key) || {
    name,
    tags,
    value: 0,
    updatedAt: 0,
  };

  prev.value += Number(value || 0);
  prev.updatedAt = Date.now();

  PHASE5_COUNTERS.set(key, prev);

  if (PHASE5_COUNTERS.size > PHASE5_METRIC_HISTORY_MAX) {
    const firstKey = PHASE5_COUNTERS.keys().next().value;
    if (firstKey) PHASE5_COUNTERS.delete(firstKey);
  }
}

function observeLatencyMetric(name, durationMs, tags = {}) {
  const key = metricKey(name, tags);
  const prev = PHASE5_LATENCIES.get(key) || {
    name,
    tags,
    count: 0,
    sum: 0,
    max: 0,
    min: Number.POSITIVE_INFINITY,
    updatedAt: 0,
  };

  const d = Number(durationMs || 0);

  prev.count += 1;
  prev.sum += d;
  prev.max = Math.max(prev.max, d);
  prev.min = Math.min(prev.min, d);
  prev.updatedAt = Date.now();

  PHASE5_LATENCIES.set(key, prev);

  if (PHASE5_LATENCIES.size > PHASE5_METRIC_HISTORY_MAX) {
    const firstKey = PHASE5_LATENCIES.keys().next().value;
    if (firstKey) PHASE5_LATENCIES.delete(firstKey);
  }
}

function logStructured(level = "info", event = "log", fields = {}) {
  const payload = {
    ts: new Date().toISOString(),
    level,
    event,
    apiVersion: API_VERSION,
    region: DEPLOY_REGION,
    deploymentColor: DEPLOYMENT_COLOR,
    ...fields,
  };

  const line = stableStringify(payload);

  if (level === "error") {
    console.error(line);
    return;
  }

  if (level === "warn") {
    console.warn(line);
    return;
  }

  console.log(line);
}

async function emitOpsAlert(kind, payload = {}, opts = {}) {
  if (!PHASE5_ALERTS_ENABLED) return null;

  const severity = String(opts.severity || "warn");
  const cooldownMs = Number(opts.cooldownMs || PHASE5_ALERT_COOLDOWN_MS);
  const dedupeSeed =
    stableStringify(opts.dedupe || payload || {}).slice(0, 500) || kind;
  const dedupeKey = `${kind}:${hashString(dedupeSeed)}`;
  const lastAt = Number(PHASE5_ALERT_DEDUPE.get(dedupeKey) || 0);

  if (Date.now() - lastAt < cooldownMs) {
    return null;
  }

  PHASE5_ALERT_DEDUPE.set(dedupeKey, Date.now());

  const alert = {
    id: `alert_${Date.now()}_${hashString(`${kind}:${Date.now()}`)}`,
    ts: Date.now(),
    kind,
    severity,
    region: DEPLOY_REGION,
    payload,
  };

  PHASE5_ALERTS_L1.unshift(alert);
  if (PHASE5_ALERTS_L1.length > PHASE5_ALERT_HISTORY_MAX) {
    PHASE5_ALERTS_L1.length = PHASE5_ALERT_HISTORY_MAX;
  }

  try {
    recordHardeningEvent(`ops_alert_${kind}`, {
      severity,
      region: DEPLOY_REGION,
      ...payload,
    });
  } catch {}

  if (redis && !opts.skipRedis) {
    try {
      await redis.lpush("ops:alerts", JSON.stringify(alert));
      await redis.ltrim("ops:alerts", 0, PHASE5_ALERT_HISTORY_MAX - 1);
    } catch {}
  }

  logStructured(severity === "error" ? "error" : "warn", "ops_alert", {
    kind,
    severity,
    payload,
  });

  return alert;
}

async function listOpsAlerts(limit = 50) {
  const max = Math.max(1, Math.min(200, Number(limit || 50)));

  if (redis) {
    try {
      const raw = await redis.lrange("ops:alerts", 0, max - 1);
      const parsed = raw
        .map((x) => safeJsonParse(x, null))
        .filter(Boolean);

      if (parsed.length) return parsed;
    } catch {}
  }

  return PHASE5_ALERTS_L1.slice(0, max);
}

async function recordOpsDrill(type, payload = {}) {
  const item = {
    id: `drill_${Date.now()}_${hashString(`${type}:${Date.now()}`)}`,
    ts: Date.now(),
    type,
    region: DEPLOY_REGION,
    payload,
  };

  PHASE5_DRILLS_L1.unshift(item);
  if (PHASE5_DRILLS_L1.length > PHASE5_ALERT_HISTORY_MAX) {
    PHASE5_DRILLS_L1.length = PHASE5_ALERT_HISTORY_MAX;
  }

  if (redis) {
    try {
      await redis.lpush("ops:drills", JSON.stringify(item));
      await redis.ltrim("ops:drills", 0, PHASE5_ALERT_HISTORY_MAX - 1);
    } catch {}
  }

  try {
    await ensureDir(PHASE5_OPS_ROOT);
    await writeJson(
      `ops/drill-${item.id}.json`,
      item
    );
  } catch {}

  logStructured("info", "ops_drill_recorded", {
    type,
    payload,
  });

  return item;
}

async function listOpsDrills(limit = 50) {
  const max = Math.max(1, Math.min(200, Number(limit || 50)));

  if (redis) {
    try {
      const raw = await redis.lrange("ops:drills", 0, max - 1);
      const parsed = raw
        .map((x) => safeJsonParse(x, null))
        .filter(Boolean);

      if (parsed.length) return parsed;
    } catch {}
  }

  return PHASE5_DRILLS_L1.slice(0, max);
}

function normalizeRouteForMetrics(route = "") {
  return String(route || "")
    .replace(/[0-9a-f]{8,}/gi, ":id")
    .replace(/\b\d+\b/g, ":n")
    .replace(/\/+/g, "/")
    .trim() || "/";
}

function getRequestActor(req) {
  const userId =
    safeStr(
      req.auth?.userId ||
        req.user?.id ||
        req.headers["x-user-id"] ||
        req.body?.userId ||
        req.query?.userId,
      64
    ) || null;

  const deviceId =
    safeStr(
      req.headers["x-device-id"] ||
        req.headers["x-install-id"] ||
        req.body?.deviceId ||
        req.body?.installId,
      120
    ) || null;

  const ip = getClientIp(req);
  const fingerprint = hashString(getClientFingerprint(req));

  return {
    userId,
    deviceId,
    ip,
    anonKey: `${ip}:${fingerprint}`,
  };
}

async function incrementSharedWindowCounter(key, windowMs = PHASE5_ABUSE_WINDOW_MS) {
  if (redis) {
    try {
      const count = await redis.incr(key);
      if (count === 1) {
        await redis.pexpire(key, windowMs);
      }
      return Number(count || 0);
    } catch (err) {
      Promise.resolve()
        .then(() =>
          emitOpsAlert(
            "redis_counter_error",
            {
              key: safeStr(key, 140),
              reason: err?.message || String(err),
            },
            { severity: "error", skipRedis: true }
          )
        )
        .catch(() => {});
    }
  }

  const current = Number(EDGE_COUNTER_L1.get(key) || 0) + 1;
  EDGE_COUNTER_L1.set(key, current);
  return current;
}

function phase5EdgeHeaders(req, res, next) {
  const global = getGlobalHealthSnapshot();
  const inboundTrace =
    safeStr(req.headers["x-trace-id"], 160) ||
    safeStr(req.headers["traceparent"], 200) ||
    null;

  req.inboundTrace = inboundTrace;
  req.edgeRegion =
    safeStr(req.headers["x-edge-region"], 60) ||
    safeStr(req.headers["x-region"], 60) ||
    null;

  res.setHeader("x-api-version", API_VERSION);
  res.setHeader("x-region", DEPLOY_REGION);
  res.setHeader("x-primary-region", PRIMARY_REGION);
  res.setHeader(
    "x-active-region",
    safeStr(global?.activeRegion || DEPLOY_REGION, 60) || DEPLOY_REGION
  );
  res.setHeader("x-deployment-color", DEPLOYMENT_COLOR);

  next();
}

async function phase5EdgeAbuseGuard(req, res, next) {
  try {
    if (shouldSkipInfraGuard(req)) return next();
    if (req.method === "OPTIONS") return next();

    const path = String(req.path || "");
    const isVision =
      path === "/vision/analyze" || path === "/api/vision/analyze";
    const isUpload =
      path === "/upload/image" || path === "/api/upload/image";
    const isWrite =
      req.method !== "GET" &&
      req.method !== "HEAD" &&
      req.method !== "OPTIONS";

    if (!isVision && !isUpload && !isWrite) {
      return next();
    }

    const actor = getRequestActor(req);
    const routeKey = normalizeRouteForMetrics(path);

    const ipLimit = isUpload
      ? PHASE5_UPLOAD_IP_MAX
      : isVision
      ? PHASE5_SCAN_IP_MAX
      : PHASE5_WRITE_IP_MAX;

    const deviceLimit = isUpload
      ? PHASE5_UPLOAD_DEVICE_MAX
      : isVision
      ? PHASE5_SCAN_DEVICE_MAX
      : PHASE5_WRITE_DEVICE_MAX;

    const userLimit = isVision
      ? PHASE5_SCAN_USER_MAX
      : PHASE5_WRITE_USER_MAX;

    const counters = [];

    counters.push({
      key: `edge:abuse:ip:${routeKey}:${actor.ip}`,
      count: await incrementSharedWindowCounter(
        `edge:abuse:ip:${routeKey}:${actor.ip}`
      ),
      limit: ipLimit,
      reason: "ip_limit",
    });

    if (actor.deviceId) {
      counters.push({
        key: `edge:abuse:device:${routeKey}:${actor.deviceId}`,
        count: await incrementSharedWindowCounter(
          `edge:abuse:device:${routeKey}:${actor.deviceId}`
        ),
        limit: deviceLimit,
        reason: "device_limit",
      });
    }

    if (actor.userId) {
      counters.push({
        key: `edge:abuse:user:${routeKey}:${actor.userId}`,
        count: await incrementSharedWindowCounter(
          `edge:abuse:user:${routeKey}:${actor.userId}`
        ),
        limit: userLimit,
        reason: "user_limit",
      });
    } else if (isVision || isUpload) {
      counters.push({
        key: `edge:abuse:anon_scan:${routeKey}:${actor.anonKey}`,
        count: await incrementSharedWindowCounter(
          `edge:abuse:anon_scan:${routeKey}:${actor.anonKey}`
        ),
        limit: PHASE5_SCAN_ANON_MAX,
        reason: "anon_scan_limit",
      });
    }

    const violated = counters.find((x) => Number(x.count || 0) > Number(x.limit || 0));

    if (!violated) return next();

    incrementMetric("abuse_block_total", {
      route: routeKey,
      reason: violated.reason,
    });

    Promise.resolve()
      .then(() =>
        emitOpsAlert(
          "abuse_block",
          {
            route: routeKey,
            reason: violated.reason,
            count: violated.count,
            limit: violated.limit,
            ip: actor.ip,
            userId: actor.userId,
            deviceId: actor.deviceId,
          },
          { severity: "warn" }
        )
      )
      .catch(() => {});

    res.setHeader("Retry-After", "60");

    return res.status(429).json({
      ok: false,
      error: "abuse_limited",
      reason: violated.reason,
    });
  } catch (err) {
    Promise.resolve()
      .then(() =>
        emitOpsAlert(
          "abuse_guard_failed",
          {
            route: req.path,
            reason: err?.message || String(err),
          },
          { severity: "error", skipRedis: true }
        )
      )
      .catch(() => {});

    return next();
  }
}

function attachIdempotentResponseCapture(res, writer) {
  const oldJson = res.json;

  res.json = function (body) {
    Promise.resolve()
      .then(() => writer(Number(res.statusCode || 200), body))
      .catch(() => {});

    return oldJson.call(this, body);
  };
}

function createIdempotencyMiddleware(scope, ttlSec = IDEMPOTENCY_TTL_SEC) {
  return async function phase5Idempotency(req, res, next) {
    if (req.method !== "POST" || !redis) return next();

    const idempotencyKey = safeStr(req.headers["idempotency-key"], 120);
    if (!idempotencyKey) return next();

    const actor = getRequestActor(req);
    const actorKey = actor.userId || actor.deviceId || actor.anonKey || "anon";
    const bodyHash = hashString(stableStringify(req.body || {}));
    const redisKey = `idem:${scope}:${actorKey}:${idempotencyKey}`;

    try {
      const existingRaw = await redis.get(redisKey);
      const existing = safeJsonParse(existingRaw, null);

      if (existing?.bodyHash && existing.bodyHash !== bodyHash) {
        return res.status(409).json({
          ok: false,
          error: "idempotency_conflict",
        });
      }

      if (existing?.status === "done" && existing?.response) {
        res.setHeader("x-idempotent-replay", "1");
        return res.status(existing.httpStatus || 200).json(existing.response);
      }

      if (existing?.status === "inflight") {
        return res.status(409).json({
          ok: false,
          error: "idempotency_inflight",
        });
      }

      const claimed = await redis.set(
        redisKey,
        JSON.stringify({
          status: "inflight",
          bodyHash,
          startedAt: Date.now(),
        }),
        "EX",
        Math.min(ttlSec, 120),
        "NX"
      );

      if (claimed !== "OK") {
        const retryRaw = await redis.get(redisKey);
        const retryValue = safeJsonParse(retryRaw, null);

        if (retryValue?.status === "done" && retryValue?.response) {
          res.setHeader("x-idempotent-replay", "1");
          return res.status(retryValue.httpStatus || 200).json(retryValue.response);
        }

        return res.status(409).json({
          ok: false,
          error: "idempotency_inflight",
        });
      }

      attachIdempotentResponseCapture(res, async (httpStatus, responseBody) => {
        try {
          await redis.set(
            redisKey,
            JSON.stringify({
              status: "done",
              bodyHash,
              httpStatus,
              response: responseBody,
              finishedAt: Date.now(),
            }),
            "EX",
            ttlSec
          );
        } catch {}
      });

      return next();
    } catch (err) {
      Promise.resolve()
        .then(() =>
          emitOpsAlert(
            "idempotency_failed",
            {
              scope,
              reason: err?.message || String(err),
            },
            { severity: "error", skipRedis: true }
          )
        )
        .catch(() => {});

      return next();
    }
  };
}

function createUploadIdempotencyMiddleware(scope, ttlSec = IDEMPOTENCY_TTL_SEC) {
  return async function phase5UploadIdempotency(req, res, next) {
    if (req.method !== "POST" || !redis) return next();

    const idempotencyKey = safeStr(req.headers["idempotency-key"], 120);
    if (!idempotencyKey) return next();

    const fileHash = Buffer.isBuffer(req.file?.buffer) ? sha256(req.file.buffer) : null;
    if (!fileHash) return next();

    const actor = getRequestActor(req);
    const actorKey = actor.userId || actor.deviceId || actor.anonKey || "anon";

    const bodyHash = hashString(
      stableStringify({
        fileHash,
        mode: req.body?.mode || null,
        propContext: req.body?.propContext || null,
      })
    );

    const redisKey = `idem:${scope}:${actorKey}:${idempotencyKey}`;

    try {
      const existingRaw = await redis.get(redisKey);
      const existing = safeJsonParse(existingRaw, null);

      if (existing?.bodyHash && existing.bodyHash !== bodyHash) {
        return res.status(409).json({
          ok: false,
          error: "idempotency_conflict",
        });
      }

      if (existing?.status === "done" && existing?.response) {
        res.setHeader("x-idempotent-replay", "1");
        return res.status(existing.httpStatus || 200).json(existing.response);
      }

      if (existing?.status === "inflight") {
        return res.status(409).json({
          ok: false,
          error: "idempotency_inflight",
        });
      }

      const claimed = await redis.set(
        redisKey,
        JSON.stringify({
          status: "inflight",
          bodyHash,
          startedAt: Date.now(),
        }),
        "EX",
        ttlSec,
        "NX"
      );

      if (claimed !== "OK") {
        const retryRaw = await redis.get(redisKey);
        const retryValue = safeJsonParse(retryRaw, null);

        if (retryValue?.status === "done" && retryValue?.response) {
          res.setHeader("x-idempotent-replay", "1");
          return res.status(retryValue.httpStatus || 200).json(retryValue.response);
        }

        return res.status(409).json({
          ok: false,
          error: "idempotency_inflight",
        });
      }

      attachIdempotentResponseCapture(res, async (httpStatus, responseBody) => {
        try {
          await redis.set(
            redisKey,
            JSON.stringify({
              status: "done",
              bodyHash,
              httpStatus,
              response: responseBody,
              finishedAt: Date.now(),
            }),
            "EX",
            ttlSec
          );
        } catch {}
      });

      return next();
    } catch (err) {
      Promise.resolve()
        .then(() =>
          emitOpsAlert(
            "upload_idempotency_failed",
            {
              scope,
              reason: err?.message || String(err),
            },
            { severity: "error", skipRedis: true }
          )
        )
        .catch(() => {});

      return next();
    }
  };
}

function getPhase5MetricsSnapshot() {
  const counters = [...PHASE5_COUNTERS.values()]
    .sort((a, b) => Number(b.updatedAt || 0) - Number(a.updatedAt || 0))
    .slice(0, PHASE5_METRIC_HISTORY_MAX);

  const latencies = [...PHASE5_LATENCIES.values()]
    .map((x) => ({
      ...x,
      avg: x.count > 0 ? Math.round((x.sum / x.count) * 100) / 100 : 0,
      min: Number.isFinite(x.min) ? x.min : 0,
    }))
    .sort((a, b) => Number(b.updatedAt || 0) - Number(a.updatedAt || 0))
    .slice(0, PHASE5_METRIC_HISTORY_MAX);

  const mem = process.memoryUsage();
  const global = getGlobalHealthSnapshot();

  return {
    ts: Date.now(),
    region: DEPLOY_REGION,
    primaryRegion: PRIMARY_REGION,
    deploymentColor: DEPLOYMENT_COLOR,
    runtime: {
      pid: process.pid,
      uptimeSec: Math.floor(process.uptime()),
      heapUsedMb: Math.round((mem.heapUsed / 1024 / 1024) * 100) / 100,
      rssMb: Math.round((mem.rss / 1024 / 1024) * 100) / 100,
      bgJobQueued: Array.isArray(BG_JOB_QUEUE) ? BG_JOB_QUEUE.length : 0,
      bgJobActive: Number(BG_JOB_ACTIVE || 0),
      redisEnabled: !!redis,
      openaiEnabled: !!openai,
    },
    global,
    counters,
    latencies,
  };
}

