    const result = await redeemReferral({
      code,
      userId,
      installId: installId || null,
      source,
    });

    if (!result?.ok) {
      return res.status(200).json(result);
    }

    const redeemerBonusScans = await addBonusScans(
      userId,
      REFERRAL_BONUS_REWARD
    );
