// round2 defined above (line ~15498)

function finitePrice(n) {
  const v = Number(n);
  return Number.isFinite(v) && v > 0 ? round2(v) : null;
}

function compactSavedItem(item = {}) {
  return {
    title: item?.title || null,
    source: item?.source || null,
    price: finitePrice(item?.totalPrice ?? item?.price),
    url: item?.url || item?.buyLink || item?.link || null,
    image: item?.image || null,
    dealScore: Number(item?.dealScore || 0),
    flipScore: Number(item?.flipScore || 0),
  };
}

function userHistoryKey(userId) {
  return `user_history:v2:${safeStr(userId, 64)}`;
}

async function saveScanHistoryRecord(userId, record = {}) {
  if (!redis || !userId) return null;

  // Phase 7: stamp canonical verdict + schema_v3 on write so legacy
  // strings never become the authoritative state of a stored scan.
  const verdict = pickCanonicalVerdictForStorage(record);

  const body = {
    id:
      safeStr(record?.id, 80) ||
      `hist_${Date.now()}_${crypto.randomBytes(4).toString("hex")}`,
    query: normalizeQuery(record?.query || "") || null,
    finalQuery: normalizeQuery(record?.finalQuery || record?.query || "") || null,
    best: record?.best ? compactSavedItem(record.best) : null,
    bestPrice: finitePrice(record?.bestPrice ?? record?.best?.totalPrice ?? record?.best?.price),
    top3: Array.isArray(record?.items)
      ? record.items.slice(0, 3).map((x) => compactSavedItem(x))
      : [],
    imageHash:
      safeStr(record?.imageHash || record?.visionIdentity?.imageHash, 128) || null,
    visionIdentity: record?.visionIdentity || null,
    prediction: record?.prediction || null,
    consensus: record?.consensus || null,
    coach: record?.coach || null,
    reasonCode: pickReasonCode(record),
    createdAt: Number(record?.createdAt || Date.now()),
    // Carry raw legacy strings in so buildFreshStoredScan can archive them.
    buySignal:     safeStr(record?.buySignal     || record?.profitIntel?.buySignal,    30) || null,
    primaryAction: safeStr(record?.primaryAction || record?.profitIntel?.primaryAction, 30) || null,
  };

  const payload = verdict
    ? buildFreshStoredScan(body, verdict)
    : { ...body, _schemaVersion: STORED_SCAN_SCHEMA_VERSION };

  await redis.lpush(userHistoryKey(userId), JSON.stringify(payload));
  await redis.ltrim(userHistoryKey(userId), 0, 199);
  return payload;
}

async function listScanHistoryRecords(userId, limit = 50) {
  if (!redis || !userId) return [];

  const rows = await redis.lrange(userHistoryKey(userId), 0, Math.max(0, limit - 1));
  // Phase 7: normalize on every load. Drop unrecoverable rows and
  // queue rewrites for any row whose schema/verdict drifted.
  const out = [];
  let dirty = false;
  /** @type {string[]} */
  const newRows = [];
  for (const raw of rows) {
    try {
      const parsed = JSON.parse(raw);
      const { scan, changed, dropped } = normalizeStoredScan(parsed, {
        source: "scan-history/list",
      });
      if (dropped) { dirty = true; continue; }
      if (changed) dirty = true;
      out.push(scan);
      newRows.push(JSON.stringify(scan));
    } catch {
      dirty = true;
    }
  }

  if (dirty) {
    // Rewrite the list so legacy / corrupted rows don't survive a hydrate.
    // newRows is in the same order as `rows`, so lpush in reverse to
    // preserve recency ordering.
    try {
      const pipe = redis.multi();
      pipe.del(userHistoryKey(userId));
      for (let i = newRows.length - 1; i >= 0; i--) {
        pipe.lpush(userHistoryKey(userId), newRows[i]);
      }
      pipe.ltrim(userHistoryKey(userId), 0, 199);
      await pipe.exec();
    } catch {}
  }

  return out;
}

function savedScanIndexKey(userId) {
  return `saved_scans:index:${safeStr(userId, 64)}`;
}

function savedScanDocKey(userId, scanId) {
  return `saved_scans:doc:${safeStr(userId, 64)}:${safeStr(scanId, 80)}`;
}

async function saveSavedScanRecord(userId, record = {}) {
  if (!redis || !userId) return null;

  const id =
    safeStr(record?.id, 80) ||
    `scan_${Date.now()}_${crypto.randomBytes(4).toString("hex")}`;

  const existingRaw = await redis.get(savedScanDocKey(userId, id));
  let existing = null;

  try {
    existing = existingRaw ? JSON.parse(existingRaw) : null;
  } catch {
    existing = null;
  }

  // Phase 7: resolve canonical verdict at write time (or carry forward
  // the canonical verdict from an existing v3 record if the writer
  // didn't supply one). buildFreshStoredScan stamps _schemaVersion: 3.
  const verdict =
    pickCanonicalVerdictForStorage(record) ??
    (isStoredScanFresh(existing) ? existing.verdict : null);

  const body = {
    id,
    query:      normalizeQuery(record?.query || record?.finalQuery || "") || null,
    finalQuery: normalizeQuery(record?.finalQuery || record?.query || "") || null,
    title:
      safeStr(record?.title, 220) ||
      safeStr(record?.best?.title, 220) ||
      null,
    imageHash:
      safeStr(record?.imageHash || record?.visionIdentity?.imageHash, 128) || null,
    // Originating scan replay ID — enables linking saved scan → outcome
    scanId: safeStr(record?.scanId, 128) || null,
    best:       record?.best ? compactSavedItem(record.best) : null,
    bestPrice:  finitePrice(record?.bestPrice ?? record?.best?.totalPrice ?? record?.best?.price),
    top3: Array.isArray(record?.items)
      ? record.items.slice(0, 3).map((x) => compactSavedItem(x))
      : [],
    visionIdentity:  record?.visionIdentity || null,
    prediction:      record?.prediction     || null,
    consensus:       record?.consensus      || null,
    // Phase 7: canonical reason code, paired with verdict for notifications.
    reasonCode:      pickReasonCode(record),
    // Snapshot of decision intelligence at time of save (legacy strings
    // archived under .legacy by buildFreshStoredScan).
    buySignal:       safeStr(record?.buySignal || record?.profitIntel?.buySignal, 30) || null,
    primaryAction:   safeStr(record?.primaryAction || record?.profitIntel?.primaryAction, 30) || null,
    profitIntelSnapshot: record?.profitIntel
      ? {
          buySignal:    record.profitIntel.buySignal,
          dealStrength: record.profitIntel.dealStrength,
          demandScore:  record.profitIntel.demandScore,
          resaleScore:  record.profitIntel.resaleScore,
          confidenceV2: record.profitIntel.confidenceV2,
          priceStats:   record.profitIntel.priceStats || null,
        }
      : null,
    // Lifecycle state of this saved scan
    lifecycleStatus: safeStr(record?.lifecycleStatus, 20) || "WATCHING",
    notes:     safeStr(record?.notes, 500) || null,
    createdAt: Number(existing?.createdAt || Date.now()),
    updatedAt: Date.now(),
  };

  const payload = verdict
    ? buildFreshStoredScan(body, verdict)
    : { ...body, _schemaVersion: STORED_SCAN_SCHEMA_VERSION };

  await redis
    .multi()
    .set(savedScanDocKey(userId, id), JSON.stringify(payload))
    .zadd(savedScanIndexKey(userId), payload.updatedAt, id)
    .exec();

  return payload;
}

async function listSavedScanRecords(userId, limit = 100) {
  if (!redis || !userId) return [];

  const ids = await redis.zrevrange(savedScanIndexKey(userId), 0, Math.max(0, limit - 1));
  if (!ids.length) return [];

  const raws = await redis.mget(ids.map((id) => savedScanDocKey(userId, id)));
  const out = [];
  /** @type {Array<[string, string]>} */
  const rewrites = [];
  /** @type {string[]} */
  const dropIds = [];

  for (let i = 0; i < raws.length; i++) {
    const raw = raws[i];
    const id  = ids[i];
    let parsed = null;
    try { parsed = raw ? JSON.parse(raw) : null; } catch { parsed = null; }

    const { scan, changed, dropped } = normalizeStoredScan(parsed, {
      source: "saved-scans/list",
    });

    if (dropped) { dropIds.push(id); continue; }
    if (changed) rewrites.push([id, JSON.stringify(scan)]);
    out.push(scan);
  }

  // Phase 7 commitment: rewrite storage immediately whenever a load
  // surfaced a non-canonical or pre-v3 record, and evict permanently
  // corrupt rows from the index.
  if (rewrites.length || dropIds.length) {
    try {
      const pipe = redis.multi();
      for (const [id, json] of rewrites) {
        pipe.set(savedScanDocKey(userId, id), json);
      }
      for (const id of dropIds) {
        pipe.del(savedScanDocKey(userId, id));
        pipe.zrem(savedScanIndexKey(userId), id);
      }
      await pipe.exec();
    } catch {}
  }

  return out;
}

// Phase 7 helper: choose the canonical verdict for a write. Order:
//   1. record.buyOrPass.verdict     — already canonical from buyOrPassEngine
//   2. record.verdict               — already canonical from a previous load
//   3. normalizeVerdict(record.buySignal)         — legacy → canonical
//   4. normalizeVerdict(record.primaryAction)
// Returns null if nothing usable was supplied. Callers that get null
// fall back to writing without a `verdict` field; the next load will
// drop the doc as unrecoverable.
function pickCanonicalVerdictForStorage(record = {}) {
  const direct = record?.buyOrPass?.verdict ?? record?.verdict;
  if (isCanonicalVerdict(direct)) return direct;
  return (
    normalizeVerdict(direct) ??
    normalizeVerdict(record?.buySignal) ??
    normalizeVerdict(record?.profitIntel?.buySignal) ??
    normalizeVerdict(record?.profitIntelSnapshot?.buySignal) ??
    normalizeVerdict(record?.primaryAction) ??
    null
  );
}

// Phase 7 helper: extract a canonical reason code, falling back through
// the various places writers might have stashed it.
function pickReasonCode(record = {}) {
  return (
    safeStr(record?.reasonCode, 80) ||
    safeStr(record?.buyOrPass?.reasonCode, 80) ||
    null
  );
}

async function deleteSavedScanRecord(userId, scanId) {
  if (!redis || !userId || !scanId) return false;

  await redis
    .multi()
    .del(savedScanDocKey(userId, scanId))
    .zrem(savedScanIndexKey(userId), scanId)
    .exec();

  return true;
}

function watchlistIndexKey(userId) {
  return `watchlist:index:${safeStr(userId, 64)}`;
}

function watchlistDocKey(userId, itemId) {
  return `watchlist:doc:${safeStr(userId, 64)}:${safeStr(itemId, 80)}`;
}

async function upsertWatchlistItem(userId, item = {}) {
  if (!redis || !userId) return null;

  const normalizedQuery = normalizeQuery(item?.query || item?.title || "");
  if (!normalizedQuery) return null;

  const id =
    safeStr(item?.id, 80) || `watch_${hashString(normalizedQuery)}`;

  const existingRaw = await redis.get(watchlistDocKey(userId, id));
  let existing = null;

  try {
    existing = existingRaw ? JSON.parse(existingRaw) : null;
  } catch {
    existing = null;
  }

  const payload = {
    id,
    query: normalizedQuery,
    title: safeStr(item?.title, 220) || normalizedQuery,
    image: safeStr(item?.image, 400) || null,
    notes: safeStr(item?.notes, 500) || null,
    targetPrice: finitePrice(item?.targetPrice),
    desiredBuyPrice: finitePrice(item?.desiredBuyPrice ?? item?.targetPrice),
    createdAt: Number(existing?.createdAt || Date.now()),
    updatedAt: Date.now(),
  };

  await redis
    .multi()
    .set(watchlistDocKey(userId, id), JSON.stringify(payload))
    .zadd(watchlistIndexKey(userId), payload.updatedAt, id)
    .exec();

  return payload;
}

async function listLocalWatchlistItems(userId, limit = 200) {
  if (!redis || !userId) return [];

  const ids = await redis.zrevrange(watchlistIndexKey(userId), 0, Math.max(0, limit - 1));
  if (!ids.length) return [];

  const raws = await redis.mget(ids.map((id) => watchlistDocKey(userId, id)));
  const out = [];

  for (const raw of raws) {
    try {
      const parsed = raw ? JSON.parse(raw) : null;
      if (parsed && typeof parsed === "object") out.push(parsed);
    } catch {}
  }

  return out;
}

async function deleteWatchlistItem(userId, itemId) {
  if (!redis || !userId || !itemId) return false;

  await redis
    .multi()
    .del(watchlistDocKey(userId, itemId))
    .zrem(watchlistIndexKey(userId), itemId)
    .exec();

  return true;
}

async function persistPhase2ScanRecord({
  userId,
  query,
  finalQuery,
  best,
  items,
  visionIdentity,
  prediction,
  consensus,
  coach,
} = {}) {
  if (!userId) return null;

  return await saveScanHistoryRecord(userId, {
    query,
    finalQuery,
    best,
    bestPrice: finitePrice(best?.totalPrice ?? best?.price),
    items,
    visionIdentity,
    prediction,
    consensus,
    coach,
  });
}

function watchStorageKey(userId, query) {
  return `watch:${safeStr(userId, 64)}:${hashString(normalizeQuery(query))}`;
}

async function loadWatchState(userId, query) {
  if (!redis || !userId || !query) return null;

  try {
    const raw = await redis.get(watchStorageKey(userId, query));
    if (!raw) return null;

    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : null;
  } catch {
    return null;
  }
}

async function saveWatchState(userId, query, value) {
  if (!redis || !userId || !query) return;

  try {
    await redis.set(watchStorageKey(userId, query), JSON.stringify(value));
  } catch {}
}

function bonusScansKey(userId) {
  return `bonus_scans:${safeStr(userId, 64)}`;
}

async function getBonusScans(userId) {
  if (!redis || !userId) return 0;

  try {
    const raw = await redis.get(bonusScansKey(userId));
    const n = Number(raw || 0);
    return Number.isFinite(n) ? n : 0;
  } catch {
    return 0;
  }
}

async function addBonusScans(userId, amount = 1) {
  if (!redis || !userId || !Number.isFinite(amount) || amount <= 0) return 0;

  try {
    const next = await redis.incrby(bonusScansKey(userId), amount);
    return Number(next || 0);
  } catch {
    return 0;
  }
}

function computeWatchDelta(prev, items = []) {
  const best = items[0] || null;

  const nextBestPrice = finitePrice(best?.totalPrice ?? best?.price);
  const prevBestPrice = finitePrice(prev?.lastBestPrice);

  const sourceChanged =
    String(prev?.bestSource || "") !== String(best?.source || "");

  const changed = prevBestPrice !== nextBestPrice || sourceChanged;

  const priceDropped =
    prevBestPrice != null &&
    nextBestPrice != null &&
    nextBestPrice < prevBestPrice;

  const dropAmount = priceDropped
    ? round2(prevBestPrice - nextBestPrice)
    : 0;

  const dropPct =
    priceDropped && prevBestPrice > 0
      ? round2((dropAmount / prevBestPrice) * 100)
      : 0;

  const newLow =
    nextBestPrice != null &&
    (!Number.isFinite(prev?.lowestSeen) || nextBestPrice < prev.lowestSeen);

  const significant =
    dropPct >= 8 ||
    dropAmount >= 10 ||
    newLow;

  return {
    changed,
    priceDropped,
    dropAmount,
    dropPct,
    newLow,
    sourceChanged,
    significant,
  };
}

function buildWatchState(query, items = [], prev = null, delta = null) {
  const best = items[0] || null;
  const bestPrice = finitePrice(best?.totalPrice ?? best?.price);
  const consensus = buildMarketConsensus(items);

  const prevLowest = Number.isFinite(prev?.lowestSeen) ? prev.lowestSeen : null;
  const prevHighest = Number.isFinite(prev?.highestSeen) ? prev.highestSeen : null;
  const prevDropCount = Number(prev?.dropCount || 0);
  const prevBiggestDrop = Number(prev?.biggestDrop || 0);

  return {
    query,
    lastBestPrice: bestPrice,
    previousBestPrice: finitePrice(prev?.lastBestPrice),
    bestSource: best?.source || null,
    bestTitle: best?.title || null,
    firstSeenAt: prev?.firstSeenAt || Date.now(),
    lastCheckedAt: Date.now(),
    lowestSeen:
      bestPrice == null
        ? prevLowest
        : prevLowest == null
        ? bestPrice
        : Math.min(prevLowest, bestPrice),
    highestSeen:
      bestPrice == null
        ? prevHighest
        : prevHighest == null
        ? bestPrice
        : Math.max(prevHighest, bestPrice),
    dropCount: delta?.priceDropped ? prevDropCount + 1 : prevDropCount,
    biggestDrop: delta?.priceDropped
      ? Math.max(prevBiggestDrop, Number(delta.dropAmount || 0))
      : prevBiggestDrop,
    volatility: resaleProbability(
      (items || []).map((it) => ({
        ...it,
        price: it?.totalPrice ?? it?.price,
      }))
    ),
    marketConfidence: consensus.consensusScore,
    lastDelta: delta || null,
  };
}

// Watch-poll lite path: Amazon-only (via SerpAPI) so /watch/poll doesn't fire
// five lanes per saved item on every app open. Mercari/Poshmark/Google
// Shopping routinely abort under the 4.5s SerpAPI timeout, Etsy 403s on most
// scans, and runWatchCheck only needs a cheapest-price signal — Amazon
// alone is sufficient for the price-drop detection that drives notifications.
// Full lanes are still used by the scan flow (/market/search and
// /market/search/stream) — only /watch/poll switches to lite.
async function mergeForWatchLite(query) {
  const normalizedQuery = selfHealQuery(normalizeQuery(query));
  if (!normalizedQuery) return [];

  const cacheKey = `watch_check|${canonicalMarketQuery(normalizedQuery)}`;
  const cached = await serpCacheGetWithRedis(cacheKey);
  if (Array.isArray(cached) && cached.length) return cached;

  if (!SERPAPI_KEY || isSourceCoolingDown("serpapi")) return [];

  let items = [];
  try {
    const amazon = await serpAmazon(normalizedQuery, { softFail: true });
    items = Array.isArray(amazon) ? amazon : [];
  } catch {
    items = [];
  }

  items = items
    .filter((x) => x && Number(x.totalPrice ?? x.price) > 0)
    .sort(
      (a, b) =>
        Number(a.totalPrice ?? a.price) - Number(b.totalPrice ?? b.price)
    );

  if (items.length) SERP_CACHE.set(cacheKey, items);
  return items;
}

async function runWatchCheck(userId, rawQuery) {
  const query = normalizeQuery(safeStr(rawQuery, 220));
  if (!userId || !query) return null;

  const prev = await loadWatchState(userId, query);

  // Lite path checks L1 + L2 internally and only fires SerpAPI Amazon
  // on full miss. SERPAPI_KEY check guards the no-source case.
  let items = await mergeForWatchLite(query);
  if (!Array.isArray(items)) items = [];

  const delta = computeWatchDelta(prev, items);
  const state = buildWatchState(query, items, prev, delta);
  const consensus = buildMarketConsensus(items);

  await saveWatchState(userId, query, state);

  const watchSignals = await recordWatchHeartbeat({
    userId,
    query,
    bestPrice: finitePrice(items[0]?.totalPrice ?? items[0]?.price),
    state,
    consensus,
  });

  await recordCrawlerRefresh(query, items, {
    reason: "watch_check",
  });

  // Derive next recommended action for this watched item
  const watchItem     = { targetPrice: null }; // anonymous watch — no per-user item context here
  const priceHistory  = []; // history not loaded at this layer (loaded via watchlistIntelligence)
  const nextAction    = buildWatchNextAction(watchItem, state.lastBestPrice, priceHistory);

  return {
    query,
    bestPrice: finitePrice(items[0]?.totalPrice ?? items[0]?.price),
    best: items[0] ?? null,
    delta,
    state,
    consensus,
    watchSignals,
    nextAction,
  };
}

