// ── Feature 7: Push Notifications ─────────────────────────────────────────────

/** Redis key for user push tokens */
function pushTokenKey(userId) { return `push_token:${safeStr(userId, 120)}`; }

/** Store Expo push token for a user */
async function storePushToken(userId, token) {
  if (!userId || !token) return;
  try {
    await redis.set(pushTokenKey(userId), String(token).trim(), "EX", 90 * 24 * 3600);
  } catch { /* non-fatal */ }
}

/** Retrieve stored push token for a user */
async function getPushToken(userId) {
  if (!userId) return null;
  try { return (await redis.get(pushTokenKey(userId))) || null; }
  catch { return null; }
}

/**
 * Send Expo Push Notification to a single token.
 * Uses the Expo Push Notifications service (no SDK needed — plain HTTP).
 */
async function sendExpoPushNotification({ token, title, body, data = {} }) {
  if (!token || !String(token).startsWith("ExponentPushToken")) return false;
  try {
    const payload = JSON.stringify({
      to: token,
      sound: "default",
      title: String(title || "Evan AI"),
      body: String(body || ""),
      data: data && typeof data === "object" ? data : {},
      priority: "high",
    });
    const controller = new AbortController();
    const t = setTimeout(() => controller.abort(), 8000);
    const r = await fetch("https://exp.host/--/api/v2/push/send", {
      method: "POST",
      headers: { "Content-Type": "application/json", Accept: "application/json" },
      body: payload,
      signal: controller.signal,
    });
    clearTimeout(t);
    const json = await r.json().catch(() => null);
    const status = json?.data?.status;
    if (status === "error") {
      console.warn("⚠️ Expo push error:", json?.data?.message);
      return false;
    }
    return true;
  } catch (err) {
    console.warn("⚠️ sendExpoPushNotification failed:", err?.message || err);
    return false;
  }
}

/** Queue push + in-app notification for a price drop */
async function notifyPriceDrop({ userId, query, bestPrice, dropAmount, dropPct, best }) {
  if (!userId) return;

  // Phase 8: notifications are GENERATED from (canonicalVerdict, reasonCode).
  // A price-drop alert is, semantically, a BUY signal — the watched price
  // came down. The builder produces clean copy with no legacy strings.
  const note = buildNotificationFromVerdict({
    verdict: "BUY",
    reasonCode: REASON_CODES.PRICE_DROP_ALERT,
    source: "price_drop",
    data: {
      query,
      bestPrice,
      dropAmount,
      dropPct,
      itemTitle: best?.title || null,
      itemSource: best?.source || null,
    },
  });

  // Compose the user-visible body around the canonical headline. Keep
  // the headline (note.body) verbatim from the builder and append
  // numeric facts only — never legacy enums.
  const dropFragment =
    dropPct != null
      ? `-${Math.round(dropPct)}%`
      : `-$${Math.round(dropAmount ?? 0)}`;
  const body = `${query} dropped to $${bestPrice ?? "?"} (${dropFragment}). ${note.body}`.trim();
  const title = `🔔 ${note.title}`;

  const dedupeKey = `price_drop:${query}:${bestPrice}`;
  const data = {
    ...note.data,
    verdict: note.verdict,
    reasonCode: note.reasonCode,
    source: best?.source || null,
    title: best?.title || null,
  };

  // In-app notification
  queueNotificationFanout({
    userId,
    kind: "price_drop",
    title,
    body,
    dedupeKey,
    data,
    cooldownMs: 12 * 60 * 60 * 1000,
  });

  // Device push notification
  try {
    const token = await getPushToken(userId);
    if (token) await sendExpoPushNotification({ token, title, body, data });
  } catch { /* non-fatal */ }
}

// ─────────────────────────────────────────────────────────────────────
// Phase 11 — Verdict drift telemetry endpoint.
//
// The client (frontend) calls this whenever it observes:
//   - server verdict ≠ what it actually rendered
//   - cached scan verdict ≠ normalized verdict
//   - any verdict-shaped string it can't normalize at all
//
// The server normalizes both sides and routes through the same sink
// the rest of the verdict_disagreement_event pipeline uses, so client
// drift is observable in the same dashboards as server drift.
//
// Body: {
//   source: "scan_complete" | "history_load" | "notification_open" | ...
//   trigger: "server-vs-client" | "cache-vs-normalized" | "ai-prompt-vs-canonical"
//   serverVerdict: <raw>      // optional — what the server claimed
//   clientVerdict: <raw>      // optional — what the client rendered
//   scanId, userId, build:    optional metadata for triage
// }
// ─────────────────────────────────────────────────────────────────────
app.post("/telemetry/verdict-disagreement", async (req, res) => {
  try {
    const source   = safeStr(req.body?.source, 100)  || "client";
    const trigger  = safeStr(req.body?.trigger, 50);
    const validTriggers = ["server-vs-client", "cache-vs-normalized", "ai-prompt-vs-canonical", "legacy-vs-canonical"];
    const finalTrigger = validTriggers.includes(trigger) ? trigger : "server-vs-client";

    reportVerdictDisagreement({
      trigger:  finalTrigger,
      source,
      expected: req.body?.serverVerdict,
      received: req.body?.clientVerdict,
      meta: {
        scanId:  safeStr(req.body?.scanId,  128) || null,
        userId:  safeStr(req.body?.userId,  64)  || null,
        build:   safeStr(req.body?.build,   40)  || null,
        platform:safeStr(req.body?.platform,32)  || null,
        screen:  safeStr(req.body?.screen,  64)  || null,
      },
    });
    return res.status(200).json({ ok: true });
  } catch (err) {
    return res.status(200).json({ ok: false, error: err?.message || "telemetry_failed" });
  }
});

// POST /push/register — store Expo push token for user
app.post("/push/register", async (req, res) => {
  try {
    const userId = safeStr(req.body?.userId, 64) || null;
    const token  = safeStr(req.body?.pushToken, 200) || null;
    if (!userId || !token) {
      return res.status(200).json({ ok: false, error: "missing_fields" });
    }
    if (!token.startsWith("ExponentPushToken")) {
      return res.status(200).json({ ok: false, error: "invalid_token_format" });
    }
    await storePushToken(userId, token);
    return res.status(200).json({ ok: true });
  } catch (e) {
    return res.status(200).json({ ok: false, error: "register_failed" });
  }
});

function validatePhase1Config() {
  const warnings = [];

  if (IS_PROD && REDIS_REQUIRED_IN_PROD && !process.env.REDIS_URL) {
    warnings.push({
      code: "missing_redis_url",
      reason: "REDIS_URL is required in production for Phase 1 shared-state safety",
    });
  }

  if (REQUIRE_EDGE_SECRET && !EDGE_SHARED_SECRET) {
    warnings.push({
      code: "missing_edge_secret",
      reason: "REQUIRE_EDGE_SECRET=true but EDGE_SHARED_SECRET is empty",
    });
  }

  if (IS_PROD && !OPS_SECRET) {
    warnings.push({
      code: "missing_ops_secret",
      reason: "OPS_SECRET is empty in production",
    });
  }

  if (IS_PROD && !process.env.API_KEY) {
    warnings.push({
      code: "missing_api_key",
      reason: "API_KEY is empty in production",
    });
  }

  return warnings;
}

const phase1ConfigWarnings = validatePhase1Config();

for (const warning of phase1ConfigWarnings) {
  logEvent("warn", "config_warning", warning);
  pushOpsAlert("config_warning", warning, 60 * 60 * 1000);
}

function validatePhase2Config() {
  const warnings = [];

  if (IS_PROD && AUTH_ENABLED && !AUTH_JWT_SECRET) {
    warnings.push({
      code: "missing_auth_jwt_secret",
      reason: "AUTH_ENABLED=true but AUTH_JWT_SECRET is empty in production",
    });
  }

  if (IS_PROD && OBJECT_STORE_PROVIDER !== "s3") {
    warnings.push({
      code: "non_s3_object_store_in_prod",
      reason: "Phase 2 production should use OBJECT_STORE_PROVIDER=s3",
    });
  }

  if (
    OBJECT_STORE_PROVIDER === "s3" &&
    (
      !OBJECT_STORE_BUCKET ||
      !OBJECT_STORE_ACCESS_KEY_ID ||
      !OBJECT_STORE_SECRET_ACCESS_KEY
    )
  ) {
    warnings.push({
      code: "incomplete_s3_object_store_config",
      reason: "OBJECT_STORE_PROVIDER=s3 but bucket/credentials are incomplete",
    });
  }

  return warnings;
}

