  // ─────────────────────────────────────────────────────────────────────────
  // ASK AI — POST /api/ask
  //
  // Conversational AI with full scan context injected as system prompt.
  // Maintains multi-turn history on client (stateless on server).
  //
  // Body: {
  //   messages: [{ role: "user"|"assistant", content: string }],  // full history
  //   scanContext: {                          // injected as system context
  //     itemName, store, price, scannedPrice, savedAmount, cheaperPct,
  //     buyVerdict, buyScore, visionConfidence, visionQuery, category,
  //     historicalLow, historicalHigh, avgMarket, totalMatches,
  //     ebaySoldComps, localComps, trendIntel, seasonalFlip, authenticityIntel
  //   }
  // }
  // Response: { ok: true, reply: string }
  // ─────────────────────────────────────────────────────────────────────────
  app.post("/api/ask", async (req, res) => {
    try {
      const { messages, scanContext } = req.body || {};
      if (!Array.isArray(messages) || messages.length === 0) {
        return res.status(200).json({ ok: false, error: "missing_messages" });
      }

      // Validate + sanitize messages (max 20 turns, 1000 chars each)
      const cleanMessages = messages
        .slice(-20)
        .filter((m) => m && (m.role === "user" || m.role === "assistant") && typeof m.content === "string")
        .map((m) => ({ role: m.role, content: String(m.content).slice(0, 1000) }));

      if (cleanMessages.length === 0) {
        return res.status(200).json({ ok: false, error: "invalid_messages" });
      }

      // Build scan context block for system prompt.
      // Phase 9: sanitize the entire context up front so no verdict-
      // shaped field survives the LLM boundary in legacy form. drifted[]
      // feeds Phase 6 telemetry — one event per non-canonical field.
      const { ctx: rawCtx } = (() => {
        const sanitized = sanitizePromptContext(scanContext || {});
        for (const d of sanitized.drifted) {
          try { reportPromptDrift(`api/ask:${d.field}`, d.canonical, d.raw); } catch {}
        }
        return sanitized;
      })();
      const ctx = rawCtx;
      const fmtPrice = (v) => (Number.isFinite(Number(v)) ? `$${Number(v).toFixed(2)}` : null);
      const fmtPct   = (v) => (Number.isFinite(Number(v)) ? `${Math.round(Number(v))}%` : null);

      const contextLines = [
        ctx.itemName        ? `Item: ${ctx.itemName}`                                                    : null,
        ctx.category        ? `Category: ${ctx.category}`                                                : null,
        ctx.store           ? `Best source: ${ctx.store}`                                                : null,
        ctx.price != null   ? `Best price found: ${fmtPrice(ctx.price)}`                                 : null,
        ctx.scannedPrice != null ? `Price user is paying: ${fmtPrice(ctx.scannedPrice)}`                  : null,
        ctx.savedAmount > 0 ? `Savings vs scanned price: ${fmtPrice(ctx.savedAmount)} (${fmtPct(ctx.cheaperPct)} less)` : null,
        // Phase 9: ctx.buyVerdict is now guaranteed canonical or null
        // (sanitizePromptContext above handled normalization + telemetry).
        // We pass it straight through — no per-call re-normalization.
        ctx.buyVerdict ? `AI deal verdict: ${ctx.buyVerdict} (score ${ctx.buyScore ?? "??"}/10)` : null,
        ctx.visionConfidence != null ? `Vision match confidence: ${fmtPct(ctx.visionConfidence * 100)}`  : null,
        ctx.visionQuery     ? `Identified as: "${ctx.visionQuery}"`                                      : null,
        ctx.historicalLow != null && ctx.historicalHigh != null
          ? `Historical price range: ${fmtPrice(ctx.historicalLow)} – ${fmtPrice(ctx.historicalHigh)}`  : null,
        ctx.avgMarket != null ? `Average market price: ${fmtPrice(ctx.avgMarket)}`                       : null,
        ctx.totalMatches    ? `Listings scanned: ${ctx.totalMatches}`                                    : null,
        ctx.ebaySoldComps?.count
          ? [
              `eBay recent sales: ${ctx.ebaySoldComps.soldCount30d ?? ctx.ebaySoldComps.count} sold (30d) · median ${fmtPrice(ctx.ebaySoldComps.median)} · range ${fmtPrice(ctx.ebaySoldComps.low)}–${fmtPrice(ctx.ebaySoldComps.high)}`,
              ctx.ebaySoldComps.avgDaysToSell ? `Avg days to sell: ${ctx.ebaySoldComps.avgDaysToSell} days` : null,
              ctx.ebaySoldComps.velocityLabel ? `Sell velocity: ${ctx.ebaySoldComps.velocityLabel}` : null,
            ].filter(Boolean).join(" · ")
          : null,
        ctx.localComps?.count
          ? `Local comps near ${ctx.localComps.location}: ${ctx.localComps.count} listings · median ${fmtPrice(ctx.localComps.median)}` : null,
        ctx.trendIntel?.buyAdvice    ? `Market trend: ${ctx.trendIntel.buyAdvice}`                       : null,
        ctx.seasonalFlip?.topSignal  ? `Seasonal signal: ${ctx.seasonalFlip.topSignal}`                  : null,
        ctx.authenticityIntel?.topSignal ? `Authenticity: ${ctx.authenticityIntel.topSignal}`            : null,
      ].filter(Boolean);

      const systemPrompt = [
        "You are Evan AI — a concise, expert resale intelligence assistant. You help users decide whether to buy, flip, or skip an item based on real market data.",
        "",
        "SCAN CONTEXT (real data from this session):",
        ...contextLines,
        "",
        "RULES:",
        "- Be direct and concise. Max 3 short paragraphs per reply.",
        "- Use the scan data above to ground every answer. Don't speculate beyond it.",
        "- Give clear buy/skip/negotiate recommendations when asked.",
        "- For negotiation questions, suggest a specific opening offer and reasoning.",
        "- For flip questions, give an estimated net profit and sell timeline if data allows.",
        "- Never say you're an AI or mention your training cutoff. Just answer.",
        "- No markdown headers. Short bullets or plain prose only.",
      ].join("\n");

      const completion = await openai.chat.completions.create({
        model: "gpt-4.1-mini",
        messages: [
          { role: "system", content: systemPrompt },
          ...cleanMessages,
        ],
        max_tokens: 320,
        temperature: 0.4,
      });

      const reply = completion.choices?.[0]?.message?.content?.trim() || "Sorry, I couldn't generate a response right now.";
      return res.json({ ok: true, reply });
    } catch (e) {
      console.error("❌ /api/ask error:", e?.message);
      return res.status(200).json({ ok: false, error: e?.message || "ask_failed" });
    }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // AUTO-LISTING GENERATOR — POST /api/listing/generate
  //
  // Generates a ready-to-post resale listing from scan context.
  // Returns: title, description, price, category, tags[], platforms[]
  //
  // Body: { scanContext }   (same shape as /api/ask)
  // Response: { ok: true, listing: { title, description, price, category, tags, platforms } }
  // ─────────────────────────────────────────────────────────────────────────
  app.post("/api/listing/generate", async (req, res) => {
    try {
      const { scanContext } = req.body || {};
      if (!scanContext || !scanContext.itemName) {
        return res.status(200).json({ ok: false, error: "missing_scan_context" });
      }

      // Phase 9: sanitize verdict-bearing fields once, then pass clean ctx forward.
      const { ctx: cleanCtx, drifted: listingDrifted } = sanitizePromptContext(scanContext);
      for (const d of listingDrifted) {
        try { reportPromptDrift(`api/listing/generate:${d.field}`, d.canonical, d.raw); } catch {}
      }
      const ctx = cleanCtx;
      const fmtPrice = (v) => (Number.isFinite(Number(v)) ? `$${Number(v).toFixed(2)}` : null);

      // Build context block
      const contextLines = [
        ctx.itemName        ? `Item: ${ctx.itemName}`                                         : null,
        ctx.category        ? `Category: ${ctx.category}`                                     : null,
        ctx.visionQuery     ? `Identified as: "${ctx.visionQuery}"`                           : null,
        ctx.price != null   ? `Best market price: ${fmtPrice(ctx.price)}`                     : null,
        ctx.scannedPrice != null ? `Current listing price: ${fmtPrice(ctx.scannedPrice)}`     : null,
        ctx.avgMarket != null ? `Avg market value: ${fmtPrice(ctx.avgMarket)}`                : null,
        ctx.historicalLow != null && ctx.historicalHigh != null
          ? `Price range: ${fmtPrice(ctx.historicalLow)}–${fmtPrice(ctx.historicalHigh)}`     : null,
        ctx.ebaySoldComps?.median
          ? `eBay median sold: ${fmtPrice(ctx.ebaySoldComps.median)}`                         : null,
        ctx.buyVerdict ? `Condition/verdict: ${ctx.buyVerdict}` : null,
        ctx.authenticityIntel?.tier ? `Authenticity tier: ${ctx.authenticityIntel.tier}`     : null,
        ctx.trendIntel?.buyAdvice ? `Market trend: ${ctx.trendIntel.buyAdvice}`              : null,
      ].filter(Boolean).join("\n");

      const systemPrompt = `You are an expert resale listing copywriter for eBay, Poshmark, and Mercari. Generate optimized listings that sell fast at top dollar.

RULES:
- Title: max 80 chars, front-load brand + model + key attributes (size, color, condition). eBay/Poshmark SEO-optimized.
- Description: 3–5 sentences. Lead with condition, list key features, end with a buyer confidence line. No fluff.
- Price: Suggest optimal sell price in USD based on market data (number only, no $ sign).
- Category: Single best-fit resale category string.
- Tags: 6–10 relevant search keywords as a JSON array of strings.
- Platforms: Best 2–3 platforms to sell on, as a JSON array (choose from: eBay, Poshmark, Mercari, StockX, GOAT, Facebook Marketplace, OfferUp, Depop).

Respond ONLY with valid JSON in exactly this shape:
{
  "title": "...",
  "description": "...",
  "price": 00.00,
  "category": "...",
  "tags": ["...", "..."],
  "platforms": ["...", "..."]
}`;

      const userMessage = `Generate a listing for this item:\n\n${contextLines}`;

      const completion = await openai.chat.completions.create({
        model: "gpt-4.1-mini",
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user",   content: userMessage },
        ],
        max_tokens: 480,
        temperature: 0.3,
        response_format: { type: "json_object" },
      });

      const raw = completion.choices?.[0]?.message?.content?.trim() || "{}";
      let listing;
      try {
        listing = JSON.parse(raw);
      } catch {
        return res.status(200).json({ ok: false, error: "parse_failed", raw });
      }

      // Normalize types
      listing.price   = Number.isFinite(Number(listing.price)) ? Number(Number(listing.price).toFixed(2)) : null;
      listing.tags     = Array.isArray(listing.tags)     ? listing.tags.slice(0, 10)     : [];
      listing.platforms = Array.isArray(listing.platforms) ? listing.platforms.slice(0, 4) : [];

      return res.json({ ok: true, listing });
    } catch (e) {
      console.error("❌ /api/listing/generate error:", e?.message);
      return res.status(200).json({ ok: false, error: e?.message || "listing_failed" });
    }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // BATCH: IDENTIFY — POST /api/batch/identify
  //
  // Lightweight JSON-body vision endpoint for batch scanning.
  // Accepts a single base64 image, runs the 3-pass vision consensus,
  // returns query + identity ready to pass to /market/search.
  //
  // Body:  { imageBase64: string }
  // Response: { ok, query, variants, confidence, category, identity }
  // ─────────────────────────────────────────────────────────────────────────
  app.post("/api/batch/identify", async (req, res) => {
    try {
      const { imageBase64 } = req.body || {};
      if (!imageBase64 || typeof imageBase64 !== "string" || imageBase64.length < 200) {
        return res.status(200).json({ ok: false, error: "imageBase64 required" });
      }

      const buf = Buffer.from(imageBase64, "base64");
      if (buf.length < 1000) {
        return res.status(200).json({ ok: false, error: "image_too_small" });
      }

      // Construct minimal file + req objects for runVisionConsensus
      const fakeFile = { buffer: buf, mimetype: "image/jpeg", size: buf.length };
      const fakeReq  = { rid: `batch_${Date.now()}_${Math.random().toString(36).slice(2, 8)}` };

      const result = await withHardTimeout(
        runVisionConsensus({ req: fakeReq, file: fakeFile, mode: "scan", propContext: "" }),
        22000,
        "batch_identify_timeout"
      );

      if (!result?.query) {
        return res.status(200).json({ ok: false, error: "vision_no_result" });
      }

      return res.json({
        ok: true,
        query:      result.query,
        variants:   Array.isArray(result.variants) ? result.variants.slice(0, 4) : [],
        confidence: clamp01(Number(result.confidence || 0)),
        category:   result.identity?.category || null,
        identity:   result.identity || null,
      });
    } catch (e) {
      console.error("❌ /api/batch/identify error:", e?.message);
      return res.status(200).json({ ok: false, error: e?.message || "identify_failed" });
    }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // BATCH: PORTFOLIO ANALYZE — POST /api/batch/analyze
  //
  // Takes an array of completed scan results and returns portfolio analysis:
  // total estimated value, top flip candidates, sell sequence recommendation.
  //
  // Body:  { items: Array<{ itemName, price, buyScore, buyVerdict, category,
  //                          ebaySoldComps, flipPrediction }> }
  // Response: { ok, totalValue, topFlips, portfolioTier, summary, sellSequence }
  // ─────────────────────────────────────────────────────────────────────────
  app.post("/api/batch/analyze", async (req, res) => {
    try {
      const { items } = req.body || {};
      if (!Array.isArray(items) || items.length === 0) {
        return res.status(200).json({ ok: false, error: "items required" });
      }

      const validItems = items
        .filter((it) => it && it.itemName)
        .slice(0, 15);

      if (validItems.length === 0) {
        return res.status(200).json({ ok: false, error: "no_valid_items" });
      }

      const fmtPrice = (v) => (Number.isFinite(Number(v)) ? `$${Number(v).toFixed(2)}` : "?");

      // Build item summaries for GPT context
      const itemLines = validItems.map((it, i) => {
        const price   = Number.isFinite(Number(it.price)) ? Number(it.price) : null;
        const verdict = it.buyVerdict || null;
        const score   = it.buyScore   || null;
        const vel     = it.ebaySoldComps?.velocityLabel || null;
        const d2s     = it.ebaySoldComps?.avgDaysToSell ?? null;
        const sold30  = it.ebaySoldComps?.soldCount30d  ?? it.ebaySoldComps?.count ?? null;
        return [
          `${i + 1}. ${it.itemName}`,
          price    ? `  Price: ${fmtPrice(price)}`                              : null,
          verdict  ? `  Deal verdict: ${verdict}${score ? ` (${score}/10)` : ""}` : null,
          vel      ? `  Velocity: ${vel}${sold30 ? ` · ${sold30} sold/30d` : ""}${d2s ? ` · ~${d2s}d to sell` : ""}` : null,
          it.category ? `  Category: ${it.category}`                            : null,
        ].filter(Boolean).join("\n");
      }).join("\n\n");

      const totalValue = validItems.reduce((sum, it) => {
        const p = Number.isFinite(Number(it.price)) ? Number(it.price) : 0;
        return sum + p;
      }, 0);

      const systemPrompt = `You are an expert resale portfolio analyst. Analyze the items below and return a JSON portfolio analysis.

RULES:
- topFlips: rank top 3 items by flip potential (buyScore + velocity + margin). Include itemName, estimatedProfit, sellPlatform, daysToSell.
- portfolioTier: "strong" (3+ hot/active velocity, avg score ≥7), "mixed" (balanced), or "weak" (mostly slow/rare, low scores).
- summary: 2 sentences max — overall portfolio quality and the single best opportunity.
- sellSequence: ordered array of itemNames from "sell first" (most liquid + profitable) to "hold or skip".
- estimatedProfit: realistic net profit after typical eBay/platform fees (≈13%). Use price from data minus 13% fees.

Return valid JSON only:
{
  "topFlips": [{ "itemName": "...", "estimatedProfit": 0.00, "sellPlatform": "...", "daysToSell": 0 }],
  "portfolioTier": "strong"|"mixed"|"weak",
  "summary": "...",
  "sellSequence": ["itemName1", "itemName2", ...]
}`;

      const completion = await openai.chat.completions.create({
        model: "gpt-4.1-mini",
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user",   content: `Portfolio items (${validItems.length} total, est. total value ${fmtPrice(totalValue)}):\n\n${itemLines}` },
        ],
        max_tokens: 600,
        temperature: 0.25,
        response_format: { type: "json_object" },
      });

      const raw = completion.choices?.[0]?.message?.content?.trim() || "{}";
      let analysis;
      try { analysis = JSON.parse(raw); } catch { analysis = {}; }

      return res.json({
        ok:            true,
        totalValue:    Math.round(totalValue * 100) / 100,
        topFlips:      Array.isArray(analysis.topFlips)      ? analysis.topFlips.slice(0, 3) : [],
        portfolioTier: analysis.portfolioTier || "mixed",
        summary:       analysis.summary       || null,
        sellSequence:  Array.isArray(analysis.sellSequence)  ? analysis.sellSequence : [],
      });
    } catch (e) {
      console.error("❌ /api/batch/analyze error:", e?.message);
      return res.status(200).json({ ok: false, error: e?.message || "batch_analyze_failed" });
    }
  });

  // -------------------- Auth: Register + Login --------------------

  const AUTH_USERS_DIR = path.join(".", "storage", "auth-users");
  const AUTH_SIGN_SECRET = process.env.AUTH_JWT_SECRET || "evan-dev-secret";

  function buildHs256Token(payload) {
    const header = { alg: "HS256", typ: "JWT" };
    const encode = (obj) =>
      Buffer.from(JSON.stringify(obj))
        .toString("base64")
        .replace(/\+/g, "-")
        .replace(/\//g, "_")
        .replace(/=+$/g, "");
    const encodedHeader = encode(header);
    const encodedPayload = encode(payload);
    const signingInput = `${encodedHeader}.${encodedPayload}`;
    const sig = crypto
      .createHmac("sha256", AUTH_SIGN_SECRET)
      .update(signingInput)
      .digest("base64")
      .replace(/\+/g, "-")
      .replace(/\//g, "_")
      .replace(/=+$/g, "");
    return `${signingInput}.${sig}`;
  }

  function authUserFilePath(email) {
    const key = crypto
      .createHash("sha256")
      .update(String(email || "").toLowerCase().trim())
      .digest("hex")
      .slice(0, 32);
    return path.join(AUTH_USERS_DIR, `${key}.json`);
  }

  app.post("/api/auth/register", async (req, res) => {
    try {
      const email = String(req.body?.email || "").toLowerCase().trim();
      const password = String(req.body?.password || "");
      const displayName = String(req.body?.displayName || "").trim();

      if (!email || !password) {
        return res.status(400).json({ ok: false, error: "email_and_password_required" });
      }

      await fs.mkdir(AUTH_USERS_DIR, { recursive: true });

      const filePath = authUserFilePath(email);
      let exists = false;
      try {
        await fs.access(filePath);
        exists = true;
      } catch {}

      if (exists) {
        return res.status(409).json({ ok: false, error: "email_taken" });
      }

      const passwordHash = await bcrypt.hash(password, 12);
      const userId = crypto.randomUUID();
      const nowSec = Math.floor(Date.now() / 1000);

      const userRecord = {
        userId,
        email,
        passwordHash,
        displayName: displayName || null,
        createdAt: new Date().toISOString(),
      };

      await fs.writeFile(filePath, JSON.stringify(userRecord, null, 2), "utf8");

      const token = buildHs256Token({
        sub: userId,
        email,
        plan: "free",
        iat: nowSec,
        exp: nowSec + 90 * 24 * 3600,
      });

      return res.json({ ok: true, token, userId, email });
    } catch (e) {
      console.error("❌ /api/auth/register error:", e?.message);
      return res.status(500).json({ ok: false, error: "register_failed" });
    }
  });

  app.post("/api/auth/login", async (req, res) => {
    try {
      const email = String(req.body?.email || "").toLowerCase().trim();
      const password = String(req.body?.password || "");

      if (!email || !password) {
        return res.status(400).json({ ok: false, error: "email_and_password_required" });
      }

      const filePath = authUserFilePath(email);
      let userRecord;
      try {
        const raw = await fs.readFile(filePath, "utf8");
        userRecord = JSON.parse(raw);
      } catch {
        return res.status(401).json({ ok: false, error: "invalid_credentials" });
      }

      const valid = await bcrypt.compare(password, userRecord.passwordHash || "");
      if (!valid) {
        return res.status(401).json({ ok: false, error: "invalid_credentials" });
      }

      const nowSec = Math.floor(Date.now() / 1000);
      const token = buildHs256Token({
        sub: userRecord.userId,
        email: userRecord.email,
        plan: "free",
        iat: nowSec,
        exp: nowSec + 90 * 24 * 3600,
      });

      return res.json({
        ok: true,
        token,
        userId: userRecord.userId,
        email: userRecord.email,
        displayName: userRecord.displayName || null,
      });
    } catch (e) {
      console.error("❌ /api/auth/login error:", e?.message);
      return res.status(500).json({ ok: false, error: "login_failed" });
    }
  });

  // -------------------- eBay Listing Auto-Post --------------------

  app.post("/api/listing/post-to-ebay", async (req, res) => {
    try {
      const {
        title,
        description,
        price,
        category,
        condition,
        imageUrls,
        ebayToken,
      } = req.body || {};

      if (!ebayToken) {
        return res.status(400).json({ ok: false, error: "ebayToken_required" });
      }
      if (!title || String(title).length > 80) {
        return res.status(400).json({
          ok: false,
          error: "title_required_max_80_chars",
        });
      }
      const parsedPrice = Number(price);
      if (!parsedPrice || parsedPrice <= 0) {
        return res.status(400).json({ ok: false, error: "price_must_be_positive" });
      }

      const conditionMap = {
        new: "NEW",
        like_new: "LIKE_NEW",
        very_good: "VERY_GOOD",
        good: "GOOD",
        acceptable: "ACCEPTABLE",
      };
      const ebayCondition = conditionMap[String(condition || "").toLowerCase()] || "USED_EXCELLENT";

      const draftBody = {
        product: {
          title: String(title).slice(0, 80),
          description: String(description || title),
          imageUrls: Array.isArray(imageUrls) ? imageUrls.slice(0, 12) : [],
          aspects: {},
        },
        condition: ebayCondition,
        categoryId: String(category || ""),
        format: "FIXED_PRICE",
        availableQuantity: 1,
        pricingSummary: {
          price: {
            value: parsedPrice.toFixed(2),
            currency: "USD",
          },
        },
      };

      const ebayResp = await fetch(
        "https://api.ebay.com/sell/listing/v1_beta/item_draft",
        {
          method: "POST",
          headers: {
            Authorization: `Bearer ${ebayToken}`,
            "Content-Type": "application/json",
            "Content-Language": "en-US",
            "Accept-Language": "en-US",
          },
          body: JSON.stringify(draftBody),
        }
      );

      const ebayData = await ebayResp.json().catch(() => ({}));

      if (!ebayResp.ok) {
        console.error("❌ eBay listing draft error:", ebayResp.status, ebayData);
        return res.status(502).json({
          ok: false,
          error: "ebay_api_error",
          status: ebayResp.status,
          details: ebayData,
        });
      }

      const listingId = ebayData.itemDraftId || ebayData.listingId || null;
      const listingUrl = listingId
        ? `https://www.ebay.com/itm/${listingId}`
        : null;

      return res.json({ ok: true, listingId, listingUrl, raw: ebayData });
    } catch (e) {
      console.error("❌ /api/listing/post-to-ebay error:", e?.message);
      return res.status(500).json({ ok: false, error: "ebay_post_failed" });
    }
  });

  // -------------------- Watchlist Server Cron --------------------

  const watchCronLastPoll = new Map();

  cron.schedule("*/30 * * * *", async () => {
    try {
      const usersDir = path.join(".", "storage", "product-scale", "users");
      let entries;
      try {
        entries = await fs.readdir(usersDir);
      } catch {
        return; // directory doesn't exist yet
      }

      const MIN_POLL_INTERVAL_MS = 25 * 60 * 1000;
      const MAX_USERS_PER_TICK = 20;
      const now = Date.now();

      let processed = 0;
      for (const entry of entries) {
        if (processed >= MAX_USERS_PER_TICK) break;
        if (!entry.endsWith(".json")) continue;

        const userId = entry.replace(/\.json$/, "");

        const lastPoll = watchCronLastPoll.get(userId) || 0;
        if (now - lastPoll < MIN_POLL_INTERVAL_MS) continue;

        let profile;
        try {
          const raw = await fs.readFile(path.join(usersDir, entry), "utf8");
          profile = JSON.parse(raw);
        } catch {
          continue;
        }

        if (!Array.isArray(profile?.watchlist) || profile.watchlist.length === 0) continue;

        watchCronLastPoll.set(userId, now);
        processed++;

        for (const item of profile.watchlist) {
          if (!item?.query) continue;
          try {
            const result = await runWatchCheck(userId, item.query);
            if (result?.delta?.priceDropped && result?.delta?.significant) {
              await notifyPriceDrop({
                userId,
                query: item.query,
                bestPrice: result.delta.bestPrice ?? result.best?.price ?? 0,
                dropAmount: result.delta.dropAmount ?? 0,
                dropPct: result.delta.dropPct ?? 0,
                best: result.best ?? null,
              });
            }
          } catch (watchErr) {
            console.warn("⚠️ watchCron item error:", userId, item.query, watchErr?.message);
          }
        }
      }

      if (processed > 0) {
        console.log(`[watchCron] Checked ${processed} user(s) at ${new Date().toISOString()}`);
      }
    } catch (e) {
      console.error("❌ watchCron error:", e?.message);
    }
  });

// ── Negotiation Co-Pilot (SSE streaming) ──────────────────────────────────
// POST /api/negotiate/chat
// Body: { messages: [{role,content}], context: {itemName, listingPrice, marketMedian, dealVerdict, itemCategory} }
// Streams GPT-4o response as SSE: data: {"chunk": "..."}\n\n
// Final: data: {"done": true}\n\n
app.post("/api/negotiate/chat", async (req, res) => {
  try {
    const { messages = [], context = {} } = req.body || {};
    const { itemName = "this item", listingPrice = null, marketMedian = null, dealVerdict = "fair", itemCategory = "" } = context;

    if (!openai) {
      return res.status(503).json({ ok: false, error: "AI not available" });
    }

    const systemPrompt = [
      "You are Evan, an expert negotiation coach for resale and thrift shopping.",
      "You help buyers get the best price through confident, data-backed negotiation.",
      `Current item: ${itemName}${itemCategory ? ` (${itemCategory})` : ""}.`,
      listingPrice ? `Asking price: $${listingPrice}.` : "",
      marketMedian ? `Market median: $${Math.round(marketMedian)}.` : "",
      dealVerdict ? `Deal assessment: ${dealVerdict}.` : "",
      "",
      "Guidelines:",
      "- Give specific dollar amounts, not ranges.",
      "- Be concise and tactical — max 3 sentences per response.",
      "- Provide exact scripts the user can say out loud.",
      "- Be direct. No filler. No fluff.",
      "- If the item is overpriced vs market, say so with confidence and give a specific counter-offer.",
    ].filter(Boolean).join("\n");

    const chatMessages = [
      { role: "system", content: systemPrompt },
      ...messages.slice(-12), // keep last 12 messages for context
    ];

    res.setHeader("Content-Type", "text/event-stream");
    res.setHeader("Cache-Control", "no-cache");
    res.setHeader("Connection", "keep-alive");
    res.setHeader("Access-Control-Allow-Origin", "*");
    res.flushHeaders();

    const stream = await openai.chat.completions.create({
      model: "gpt-4.1-mini",
      messages: chatMessages,
      stream: true,
      max_tokens: 300,
      temperature: 0.7,
    });

    for await (const chunk of stream) {
      const text = chunk.choices?.[0]?.delta?.content;
      if (text) {
        res.write(`data: ${JSON.stringify({ chunk: text })}\n\n`);
      }
    }

    res.write(`data: ${JSON.stringify({ done: true })}\n\n`);
    res.end();
  } catch (e) {
    console.error("❌ /api/negotiate/chat error:", e?.message);
    try {
      res.write(`data: ${JSON.stringify({ error: e?.message || "chat_failed" })}\n\n`);
      res.end();
    } catch {}
  }
});

// ── Personalized Flip Profile ──────────────────────────────────────────────
// POST /api/profile/flip
// Body: { scanHistory: [{itemName, category, price, savedAmount, timestamp}] }
// Returns: { personality, topCategory, avgMargin, totalFlips, badges, advice }
app.post("/api/profile/flip", async (req, res) => {
  try {
    const { scanHistory = [] } = req.body || {};

    if (!Array.isArray(scanHistory) || scanHistory.length === 0) {
      return res.json({ ok: true, personality: "Explorer", topCategory: null, avgMargin: 0, totalFlips: 0, badges: [], advice: "Scan more items to unlock your flip profile." });
    }

    // Tally by category
    const catCounts = {};
    let totalSaved = 0;
    let totalWithSavings = 0;

    for (const item of scanHistory) {
      const cat = (item.category || item.itemCategory || "general").toLowerCase();
      catCounts[cat] = (catCounts[cat] || 0) + 1;
      if (Number.isFinite(item.savedAmount) && item.savedAmount > 0) {
        totalSaved += item.savedAmount;
        totalWithSavings++;
      }
    }

    const topCategory = Object.entries(catCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || "general";
    const avgMargin = totalWithSavings > 0 ? Math.round(totalSaved / totalWithSavings) : 0;
    const totalFlips = scanHistory.length;

    const PERSONALITIES = {
      sneakers: { name: "Sneaker Arbitrageur", icon: "👟", advice: "Focus on DS (deadstock) pairs — they command 40-80% premiums over beaters." },
      electronics: { name: "Tech Flipper", icon: "📱", advice: "Watch for generation gaps — last-gen models drop 30% the week a new model drops." },
      outerwear: { name: "Streetwear Hunter", icon: "🧥", advice: "Buy pre-season (Aug for winter gear) and sell in-season for 25-35% more." },
      watches: { name: "Watch Arb Pro", icon: "⌚", advice: "Reference numbers are everything — verify before buying, fakes are common." },
      bags: { name: "Luxury Bag Flipper", icon: "👜", advice: "Provenance matters — full set (box, dustbag, receipt) commands 20-40% premium." },
      audio: { name: "Audio Gear Scalper", icon: "🎧", advice: "Limited colorways and collaborations are your edge — check release calendars weekly." },
      general: { name: "Thrift Generalist", icon: "🔍", advice: "You're casting a wide net — consider specializing in 1-2 categories to increase edge." },
    };

    const personality = PERSONALITIES[topCategory] || PERSONALITIES.general;

    const badges = [];
    if (totalFlips >= 5) badges.push({ icon: "🔥", label: "Power Scanner" });
    if (totalFlips >= 20) badges.push({ icon: "🏆", label: "Flip Elite" });
    if (avgMargin >= 30) badges.push({ icon: "💰", label: "Margin Master" });
    if (totalSaved >= 200) badges.push({ icon: "💎", label: "$200+ Saved" });
    if (totalSaved >= 1000) badges.push({ icon: "🚀", label: "$1K Saver" });

    return res.json({
      ok: true,
      personality: personality.name,
      personalityIcon: personality.icon,
      topCategory,
      avgMargin,
      totalSaved: Math.round(totalSaved),
      totalFlips,
      badges,
      advice: personality.advice,
    });
  } catch (e) {
    console.error("❌ /api/profile/flip error:", e?.message);
    return res.status(500).json({ ok: false, error: "profile_failed" });
  }
});

