// WS7: Weekly audit cron — runs every Monday ~03:00 UTC
// Phase 11: Daily drift scan cron — runs every day ~02:00 UTC
// Checks once per minute whether we're in the target window.
if (redis) {
  warmSuppressionCache().catch(() => {}); // warm on startup
  setInterval(async () => {
    try {
      const now = new Date();
      // Weekly audit: Monday 03:00 UTC
      if (now.getUTCDay() === 1 && now.getUTCHours() === 3 && now.getUTCMinutes() < 5) {
        await enqueueAuditSystem(redis).catch(() => {});
      }
      // Daily drift scan: every day 02:00 UTC
      if (now.getUTCHours() === 2 && now.getUTCMinutes() < 5) {
        await enqueueDriftScan(redis).catch(() => {});
      }
    } catch { /* non-fatal */ }
  }, 60_000).unref?.();

  // Re-warm suppression cache every 5 minutes
  setInterval(() => warmSuppressionCache().catch(() => {}), SUPPRESSION_CACHE_TTL_MS).unref?.();

  // Phase 19: warm adaptive threshold cache at startup
  refreshThresholdCache(redis).catch(() => {});

  // Phase 19: anomaly detection loop — runs every 30 minutes
  setInterval(() => {
    runAnomalyDetection(redis).catch(() => {});
  }, 30 * 60_000).unref?.();

  // Phase 19: self-healing loop — runs every 2 hours
  setInterval(() => {
    runSelfHealingCycle(redis, { log: (msg) => console.log(msg) }).catch(() => {});
  }, 2 * 3600 * 1000).unref?.();

  // Phase 19: refresh adaptive threshold cache every 30 minutes
  setInterval(() => {
    refreshThresholdCache(redis).catch(() => {});
  }, 30 * 60_000).unref?.();

  // Phase 2: Seed counterfeit memory with known fake patterns (idempotent)
  seedCounterfeitMemory(redis).catch(() => {});
}

startLeaderOnlyLoops();

server.keepAliveTimeout = Number(process.env.KEEP_ALIVE_TIMEOUT_MS || 5000);
server.headersTimeout = Number(process.env.HEADERS_TIMEOUT_MS || 65000);
server.requestTimeout = Number(process.env.REQUEST_TIMEOUT_MS || 30000);
server.maxRequestsPerSocket = Number(process.env.MAX_REQUESTS_PER_SOCKET || 1000);

function shutdown(sig) {
  console.log(`🛑 ${sig} received. Shutting down...`);

  try {
    leaderElection.stop();
  } catch {}

  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 8000).unref();
}

process.on("SIGTERM", () => shutdown("SIGTERM"));
process.on("SIGINT", () => shutdown("SIGINT"));

server.on("clientError", (err, socket) => {
  // ECONNRESET / ECONNABORTED = client closed the connection (SSE teardown,
  // app backgrounded, iOS timeout). Not a server error — destroy quietly.
  const code = err?.code || "";
  if (code === "ECONNRESET" || code === "ECONNABORTED" || !socket.writable) {
    try { socket.destroy(); } catch {}
    return;
  }
  console.warn("CLIENT ERROR:", err?.message || err);
  try {
    socket.end("HTTP/1.1 400 Bad Request\r\n\r\n");
  } catch {}
});

process.on("warning", (warning) => {
  console.warn("PROCESS WARNING:", {
    name: warning?.name || "warning",
    message: warning?.message || String(warning),
    stack: warning?.stack || null,
  });

  Promise.resolve()
    .then(() =>
      emitOpsAlert(
        "process_warning",
        {
          name: warning?.name || "warning",
          message: warning?.message || String(warning),
        },
        { severity: "warn", skipRedis: true, cooldownMs: 60_000 }
      )
    )
    .catch(() => {});
});

// -------------------- Crash protection --------------------
process.on("unhandledRejection", (err) => {
  console.error("UNHANDLED REJECTION:", err);
  recordHardeningEvent("unhandled_rejection", {
    error: err?.message || String(err),
  });
  incrementMetric("process_unhandled_rejection_total", {});
  Promise.resolve()
    .then(() =>
      emitOpsAlert(
        "unhandled_rejection",
        {
          error: err?.message || String(err),
        },
        { severity: "error", skipRedis: true, cooldownMs: 30_000 }
      )
    )
    .catch(() => {})
    .finally(() => {
      if (IS_PROD) shutdown("UNHANDLED_REJECTION");
    });
});

process.on("uncaughtException", (err) => {
  console.error("UNCAUGHT EXCEPTION:", err);
  recordHardeningEvent("uncaught_exception", {
    error: err?.message || String(err),
  });
  incrementMetric("process_uncaught_exception_total", {});
  Promise.resolve()
    .then(() =>
      emitOpsAlert(
        "uncaught_exception",
        {
          error: err?.message || String(err),
        },
        { severity: "error", skipRedis: true, cooldownMs: 30_000 }
      )
    )
    .catch(() => {})
    .finally(() => {
      shutdown("UNCAUGHT_EXCEPTION");
    });
});

// ── POST /intel/rivalry ─────────────────────────────────────────────────
app.post("/intel/rivalry", (req, res) => {
  try {
    const { query = "", category = "", userId = "anon" } = req.body || {};
    const key = (category || query).toLowerCase().replace(/\s+/g, "_").slice(0, 60);
    if (!key) return res.json({ ok: true, count: 0 });

    const now = Date.now();
    const cutoff = now - RIVALRY_TTL_MS;

    // Get or create entry, prune old
    let entries = (RIVALRY_MAP.get(key) || []).filter(e => e.ts > cutoff);

    // Add this user if not already present in window
    const alreadyTracked = entries.some(e => e.userId === userId);
    if (!alreadyTracked) {
      entries.push({ userId, ts: now });
    }
    RIVALRY_MAP.set(key, entries);

    // Prune map if too large
    if (RIVALRY_MAP.size > 5000) {
      for (const [k, v] of RIVALRY_MAP.entries()) {
        if (v.every(e => e.ts <= cutoff)) RIVALRY_MAP.delete(k);
      }
    }

    // Return count excluding this user
    const othersCount = entries.filter(e => e.userId !== userId).length;
    return res.json({ ok: true, count: othersCount, window: "2h" });
  } catch (err) {
    return res.json({ ok: true, count: 0 });
  }
});

// ── POST /intel/dead-stock ──────────────────────────────────────────────
app.post("/intel/dead-stock", (req, res) => {
  try {
    const { listingPrice, daysListed = 0, avgMarket = null, itemName = "" } = req.body || {};
    const price = Number(listingPrice);
    const days = Number(daysListed);
    const market = Number(avgMarket) || null;

    if (!price || days < 14) return res.json({ ok: true, isDeadStock: false });

    const leverage = Math.min(0.45, (days / 180) * 0.35 + (market && price > market * 1.05 ? 0.10 : 0));
    const offerPrice = Math.round(price * (1 - leverage));
    const urgencyLevel = days >= 60 ? "high" : days >= 30 ? "medium" : "low";

    let message;
    if (days >= 60) message = `Listed ${days} days. Seller is motivated — they need this gone.`;
    else if (days >= 30) message = `Listed ${days} days with no buyer. Room to negotiate.`;
    else message = `Listed ${days} days. Worth a low offer.`;

    const leverageBar = Math.round((leverage || 0) * 100);
    const negotiationScript = `Hi, I noticed this has been listed for ${days} days. I can offer $${offerPrice} for a quick, hassle-free sale today.`;

    return res.json({
      ok: true,
      isDeadStock: true,
      daysListed: days,
      suggestedOffer: offerPrice,
      leveragePct: Math.round(leverage * 100),
      urgencyLevel,
      message,
      leverageBar,
      negotiationScript,
    });
  } catch (err) {
    return res.json({ ok: true, isDeadStock: false });
  }
});

