app.post("/api/outcomes/:scanId", bodySchemaMiddleware(SCHEMAS.outcomeUpdate), async (req, res) => {
  try {
    const scanId = safeStr(req.params?.scanId, 128);
    if (!scanId) return res.status(400).json({ ok: false, error: "missing_scan_id" });

    const outcome = await recordOutcome(scanId, {
      ...req.body,
      userId:   safeStr(req.body?.userId   || req.query?.userId,   128) || null,
      deviceId: safeStr(req.body?.deviceId || req.query?.deviceId, 128) || null,
      guestId:  safeStr(req.body?.guestId  || req.query?.guestId,  128) || null,
    });

    const prediction = await getPredictionSnapshot(scanId);
    console.log("💰 OUTCOME_RECORDED", {
      scanId,
      userId:           outcome?.userId || null,
      bought:           outcome?.bought,
      listed:           outcome?.listed,
      sold:             outcome?.sold,
      realizedProfit:   outcome?.realizedProfit,
      directionCorrect: outcome?.predictionError?.directionCorrect,
    });
    if (outcome?.sold === true && outcome?.realizedProfit != null) {
      console.log("📈 OUTCOME_PROFIT_COMPUTED", {
        scanId,
        actualBuyPrice:  outcome.actualBuyPrice,
        actualSellPrice: outcome.actualSellPrice,
        actualFees:      outcome.actualFees,
        shippingCost:    outcome.shippingCost,
        realizedProfit:  outcome.realizedProfit,
      });
    }

    return res.json({ ok: true, scanId, outcome, prediction });
  } catch (e) {
    console.warn("⚠️ outcome_record_failed", { scanId: req.params?.scanId, error: e?.message || String(e) });
    return res.status(500).json({ ok: false, error: "outcome_record_failed" });
  }
});

setInterval(() => {
  const used = process.memoryUsage().heapUsed / 1024 / 1024;

  if (used > 700) {
    console.warn("⚠️ High memory usage detected:", used.toFixed(1), "MB");
    incrementMetric("high_memory_total", {});

    Promise.resolve()
      .then(() =>
        emitOpsAlert(
          "high_memory",
          {
            heapUsedMb: Number(used.toFixed(1)),
          },
          { severity: "warn", cooldownMs: 60_000, skipRedis: true }
        )
      )
      .catch(() => {});

    visionCache.prune(0.5);
    SERP_CACHE.prune(0.5);
    RESEARCH_CACHE.prune(0.5);
    LOCAL_CACHE.prune(0.5);
  }
}, 30000);

// ── Phase 15: Category Intelligence daily refresh job ─────────────────────────
// Runs at 04:00 UTC via a 1-minute poll that checks the hour.
// Lightweight: only stores static calendar events that may have shifted.
// Per-user identity data does NOT need backfill — it accumulates via outcomes.
{
  let _catIntelLastRun = 0;
  setInterval(() => {
    const now  = new Date();
    const utcH = now.getUTCHours();
    const utcM = now.getUTCMinutes();
    // Run once per day at 04:00–04:01 UTC
    if (utcH !== 4 || utcM > 1) return;
    const todayMidnight = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate());
    if (_catIntelLastRun >= todayMidnight) return;
    _catIntelLastRun = todayMidnight;

    // Pre-cache calendar contexts for high-volume categories
    const catsToRefresh = ["sneakers", "watches", "electronics", "handbags", "trading_cards"];
    Promise.all(
      catsToRefresh.map((cat) =>
        import("./src/categoryEventCalendar.js")
          .then(({ getCategoryCalendarContext }) => getCategoryCalendarContext(redis, cat))
          .catch(() => null)
      )
    )
      .then(() => console.log("[Phase15] Category calendar contexts refreshed"))
      .catch(() => {});
  }, 60_000); // check every minute
}
